import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined;
};

export const db =
  globalForPrisma.prisma ||
  new PrismaClient({
    log: process.env.NODE_ENV === "development" ? ["error", "warn"] : ["error"],
  });

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = db;

import { NextResponse } from "next/server";
import type { Role } from "@prisma/client";
import { db } from "./db";
import { randomToken } from "./crypto";
import { signToken } from "./jwt";
import { getClientIp } from "./http";

export const SESSION_COOKIE_NAME = "token";
export const SESSION_TTL_MS = 7 * 24 * 60 * 60 * 1000;
export const SESSION_TTL_SECONDS = Math.floor(SESSION_TTL_MS / 1000);

export interface SessionUserCore {
  id: string;
  email: string;
  role: string;
}

export function deviceNameFromUserAgent(userAgent?: string | null) {
  if (!userAgent) return "Unknown Device";
  if (userAgent.includes("Windows")) return "Windows Device";
  if (userAgent.includes("Mac")) return "macOS Device";
  if (userAgent.includes("Linux")) return "Linux Device";
  if (userAgent.includes("Android")) return "Android Device";
  if (userAgent.includes("iPhone") || userAgent.includes("iPad")) return "iOS Device";
  return "Browser Session";
}

export async function createSessionToken(user: SessionUserCore, req: Request, options?: { deviceName?: string; expiresMs?: number }) {
  const sessionId = randomToken(24);
  const token = signToken({
    userId: user.id,
    email: user.email,
    role: user.role as Role,
    sessionId,
  });

  await db.session.create({
    data: {
      sessionToken: token,
      userId: user.id,
      userAgent: req.headers.get("user-agent"),
      ip: getClientIp(req),
      deviceName: options?.deviceName ?? deviceNameFromUserAgent(req.headers.get("user-agent")),
      expiresAt: new Date(Date.now() + (options?.expiresMs ?? SESSION_TTL_MS)),
    },
  });

  return { token, sessionId };
}

export function setSessionCookie(response: NextResponse, token: string) {
  response.cookies.set(SESSION_COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: SESSION_TTL_SECONDS,
    path: "/",
  });
}

export function clearSessionCookie(response: NextResponse) {
  response.cookies.set(SESSION_COOKIE_NAME, "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
}

export function clearPendingOAuthCookie(response: NextResponse) {
  response.cookies.set("pending_oauth", "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
}

export async function destroySession(token: string | null | undefined) {
  if (!token) return;
  await db.session.deleteMany({ where: { sessionToken: token } }).catch(() => undefined);
}

import jwt from "jsonwebtoken";
import type { Role } from "@prisma/client";

const JWT_SECRET = process.env.JWT_SECRET;

function getJwtSecret(): jwt.Secret {
  if (!JWT_SECRET || JWT_SECRET.length < 32) {
    throw new Error("JWT_SECRET must be set to a high-entropy secret of at least 32 characters");
  }

  return JWT_SECRET;
}

export interface JWTPayload {
  userId: string;
  email: string;
  role: Role;
  sessionId: string;
}

export function signToken(payload: Omit<JWTPayload, "sessionId"> & { sessionId: string }): string {
  return jwt.sign(payload, getJwtSecret(), {
    expiresIn: "7d",
    issuer: "firelab",
    audience: "firelab-web",
  });
}

export function verifyToken(token: string): JWTPayload | null {
  try {
    return jwt.verify(token, getJwtSecret(), {
      issuer: "firelab",
      audience: "firelab-web",
    }) as JWTPayload;
  } catch {
    return null;
  }
}

import { db } from "@/lib/db";
import { decrypt, encrypt } from "@/lib/crypto";
import { getOAuthRedirectUri } from "@/lib/oauth-redirect";
import crypto from "crypto";

const DISCORD_TOKEN_URL = "https://discord.com/api/oauth2/token";
const DISCORD_USER_URL = "https://discord.com/api/users/@me";
const DISCORD_AUTH_URL = "https://discord.com/api/oauth2/authorize";
const TOKEN_REFRESH_LEEWAY_MS = Number(process.env.DISCORD_TOKEN_REFRESH_LEEWAY_MS || 60_000);
const DISCORD_API_TIMEOUT_MS = Number(process.env.DISCORD_API_TIMEOUT_MS || 8_000);

export type DiscordTokenData = {
  access_token: string;
  refresh_token?: string;
  expires_in?: number;
  scope?: string;
  token_type?: string;
};

export type DiscordUser = {
  id: string;
  username: string;
  global_name?: string | null;
  avatar?: string | null;
  email?: string | null;
};

export class DiscordOAuthError extends Error {
  constructor(public readonly code: string, message: string) {
    super(message);
    this.name = "DiscordOAuthError";
  }
}

export function assertDiscordOAuthConfig() {
  const missing: string[] = [];
  if (!process.env.DISCORD_CLIENT_ID) missing.push("DISCORD_CLIENT_ID");
  if (!process.env.DISCORD_CLIENT_SECRET) missing.push("DISCORD_CLIENT_SECRET");
  if (!process.env.DISCORD_REDIRECT_URI && !process.env.OAUTH_REDIRECT_ORIGIN && !process.env.NEXT_PUBLIC_APP_URL) missing.push("DISCORD_REDIRECT_URI or OAUTH_REDIRECT_ORIGIN");

  if (missing.length > 0) {
    throw new DiscordOAuthError("discord-config", `Discord OAuth is not configured: ${missing.join(", ")}`);
  }
}

export function generatePkcePair() {
  const verifier = crypto.randomBytes(32).toString("base64url");
  const challenge = crypto.createHash("sha256").update(verifier).digest("base64url");
  return { verifier, challenge };
}

export function buildDiscordAuthorizationUrl(state: string, codeChallenge?: string) {
  assertDiscordOAuthConfig();

  const params = new URLSearchParams({
    client_id: process.env.DISCORD_CLIENT_ID || "",
    redirect_uri: getOAuthRedirectUri("discord"),
    response_type: "code",
    scope: "identify email",
    state,
  });

  if (codeChallenge) {
    params.set("code_challenge", codeChallenge);
    params.set("code_challenge_method", "S256");
  }

  return `${DISCORD_AUTH_URL}?${params.toString()}`;
}

export async function exchangeCodeForToken(code: string, codeVerifier?: string) {
  assertDiscordOAuthConfig();

  const body = new URLSearchParams({
    client_id: process.env.DISCORD_CLIENT_ID || "",
    client_secret: process.env.DISCORD_CLIENT_SECRET || "",
    grant_type: "authorization_code",
    code,
    redirect_uri: getOAuthRedirectUri("discord"),
  });

  if (codeVerifier) body.set("code_verifier", codeVerifier);

  const res = await fetchWithTimeout(DISCORD_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });

  if (!res.ok) throw new DiscordOAuthError("discord-token-exchange", "Discord token exchange failed");

  const data = (await res.json()) as DiscordTokenData;
  if (!data.access_token) throw new DiscordOAuthError("discord-token-missing", "Discord access token missing");
  return data;
}

export async function fetchDiscordUser(accessToken: string) {
  const res = await fetchWithTimeout(DISCORD_USER_URL, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (res.status === 401) throw new DiscordOAuthError("discord-invalid-token", "Discord access token is invalid or expired");
  if (!res.ok) throw new DiscordOAuthError("discord-user-fetch", "Discord user fetch failed");

  return res.json() as Promise<DiscordUser>;
}

export function discordAvatarUrl(user: { id: string; avatar?: string | null }) {
  if (!user.avatar) return null;
  const extension = user.avatar.startsWith("a_") ? "gif" : "png";
  return `https://cdn.discordapp.com/avatars/${user.id}/${user.avatar}.${extension}`;
}

export function discordDisplayName(user: DiscordUser, email?: string | null) {
  return user.global_name || user.username || (email ? email.split("@")[0] : "Discord user");
}

export async function getDiscordLinkedAccount(userId: string) {
  return db.linkedAccount.findFirst({
    where: { userId, provider: "DISCORD" },
    select: {
      id: true,
      accessTokenEncrypted: true,
      refreshTokenEncrypted: true,
      expiresAt: true,
      scopes: true,
    },
  });
}

export async function getFreshDiscordAccessToken(userId: string) {
  const account = await getDiscordLinkedAccount(userId);
  if (!account?.accessTokenEncrypted) throw new DiscordOAuthError("discord-refresh-missing", "Discord access token is not available");

  const expiresAt = account.expiresAt?.getTime();
  if (expiresAt && expiresAt <= Date.now() + TOKEN_REFRESH_LEEWAY_MS) {
    return refreshDiscordToken(userId);
  }

  return {
    accessToken: decrypt(account.accessTokenEncrypted),
    expiresAt: account.expiresAt,
    scopes: Array.isArray(account.scopes) ? account.scopes : [],
  };
}

export async function refreshDiscordToken(userId: string) {
  assertDiscordOAuthConfig();

  const account = await getDiscordLinkedAccount(userId);
  if (!account?.refreshTokenEncrypted) throw new DiscordOAuthError("discord-refresh-missing", "Discord refresh token is not available");

  const scopes = Array.isArray(account.scopes) && account.scopes.length > 0 ? account.scopes.join(" ") : "identify email";
  const body = new URLSearchParams({
    client_id: process.env.DISCORD_CLIENT_ID || "",
    client_secret: process.env.DISCORD_CLIENT_SECRET || "",
    grant_type: "refresh_token",
    refresh_token: decrypt(account.refreshTokenEncrypted),
    scope: scopes,
  });

  const res = await fetchWithTimeout(DISCORD_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });

  if (!res.ok) throw new DiscordOAuthError("discord-refresh-failed", "Discord token refresh failed");

  const data = (await res.json()) as DiscordTokenData;
  if (!data.access_token) throw new DiscordOAuthError("discord-refresh-token-missing", "Discord refreshed access token missing");

  const expiresAt = data.expires_in ? new Date(Date.now() + data.expires_in * 1000) : null;
  const scopesList = data.scope ? data.scope.split(" ").filter(Boolean) : Array.isArray(account.scopes) ? account.scopes : ["identify", "email"];

  await db.linkedAccount.update({
    where: { id: account.id },
    data: {
      accessTokenEncrypted: encrypt(data.access_token),
      refreshTokenEncrypted: data.refresh_token ? encrypt(data.refresh_token) : account.refreshTokenEncrypted,
      expiresAt,
      scopes: scopesList,
      lastSyncedAt: new Date(),
    },
  });

  return {
    accessToken: data.access_token,
    expiresAt,
    scopes: scopesList,
  };
}

export async function getDiscordUserWithFreshToken(userId: string) {
  const freshToken = await getFreshDiscordAccessToken(userId);

  try {
    return await fetchDiscordUser(freshToken.accessToken);
  } catch (error) {
    if (!(error instanceof DiscordOAuthError) || error.code !== "discord-invalid-token") throw error;
    const refreshed = await refreshDiscordToken(userId);
    return fetchDiscordUser(refreshed.accessToken);
  }
}

async function fetchWithTimeout(input: string, init?: RequestInit) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), DISCORD_API_TIMEOUT_MS);

  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(timeout);
  }
}

import Redis from "ioredis";

export const redis = new Redis(process.env.REDIS_URL || "", {
  lazyConnect: true,
  maxRetriesPerRequest: 1,
  enableReadyCheck: true,
});

redis.on("error", (error) => {
  if (process.env.NODE_ENV === "development") {
    console.warn("Redis connection unavailable; using in-memory fallback.", error.message);
  }
});

export async function connectRedis() {
  if (process.env.REDIS_URL && redis.status === "wait") {
    await redis.connect();
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { isAllowedHost } from "./lib/domains";

const securityHeaders: Record<string, string> = {
  "X-DNS-Prefetch-Control": "on",
  "Strict-Transport-Security": "max-age=63072000; includeSubDomains; preload",
  "X-Frame-Options": "DENY",
  "X-Content-Type-Options": "nosniff",
  "Referrer-Policy": "strict-origin-when-cross-origin",
  "Permissions-Policy": "camera=(), microphone=(), geolocation=()",
  "Content-Security-Policy": [
    "default-src 'self'",
    "script-src 'self' 'unsafe-eval' 'unsafe-inline'",
    "style-src 'self' 'unsafe-inline'",
    "img-src 'self' data: https: blob:",
    "font-src 'self' data:",
    "connect-src 'self' https://discord.com https://cdn.discordapp.com https://accounts.google.com https://oauth2.googleapis.com https://www.googleapis.com https://github.com https://api.github.com",
    "frame-ancestors 'none'",
  ].join("; "),
};

function isUnsafeMethod(method: string) {
  return !["GET", "HEAD", "OPTIONS", "TRACE"].includes(method);
}

function verifyCsrf(request: NextRequest): boolean {
  if (!isUnsafeMethod(request.method)) return true;
  if (process.env.NODE_ENV !== "production") return true;

  const origin = request.headers.get("origin");
  const host = request.headers.get("host");
  const referer = request.headers.get("referer");

  if (origin) {
    try {
      return isAllowedHost(new URL(origin).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  if (referer) {
    try {
      return isAllowedHost(new URL(referer).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  return true;
}

function redirectToLogin(request: NextRequest) {
  const loginUrl = new URL("/auth/login", request.url);
  const path = `${request.nextUrl.pathname}${request.nextUrl.search}`;
  loginUrl.searchParams.set("callbackUrl", path);
  return NextResponse.redirect(loginUrl);
}

export function middleware(request: NextRequest) {
  const response = NextResponse.next();

  for (const [key, value] of Object.entries(securityHeaders)) {
    response.headers.set(key, value);
  }

  if (
    request.nextUrl.pathname.startsWith("/dashboard") &&
    !request.cookies.get("token")?.value
  ) {
    return redirectToLogin(request);
  }

  if (!verifyCsrf(request)) {
    return NextResponse.json(
      { error: "CSRF validation failed" },
      { status: 403, headers: securityHeaders },
    );
  }

  return response;
}

export const config = {
  matcher: ["/((?!_next/static|_next/image|favicon.ico|api/openapi).*)"],
};

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatBytes(bytes: number, decimals = 2) {
  if (!+bytes) return "0 Bytes";
  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ["Bytes", "KB", "MB", "GB", "TB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(dm))} ${sizes[i]}`;
}

export function formatNumber(num: number) {
  return new Intl.NumberFormat().format(num);
}

export function formatCurrency(value: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0,
  }).format(value);
}

export function formatCompactNumber(value: number) {
  return new Intl.NumberFormat("en-US", {
    notation: "compact",
    maximumFractionDigits: 1,
  }).format(value);
}

import { db } from "./db";
import { decrypt, encrypt, signPayload } from "./crypto";

const WEBHOOK_EVENTS = new Set([
  "key.redeemed",
  "key.expired",
  "hwid.reset",
  "license.blacklisted",
  "script.updated",
]);

export function validateWebhookUrl(url: string): string | null {
  try {
    const parsed = new URL(url);
    if (!["http:", "https:"].includes(parsed.protocol))
      return "Only HTTP and HTTPS endpoints are allowed";
    if (
      parsed.hostname === "localhost" ||
      parsed.hostname === "127.0.0.1" ||
      parsed.hostname === "::1"
    )
      return null;
    if (
      /^(10\.|172\.(1[6-9]|2\d|3[0-1])\.|192\.168\.|169\.254\.)/.test(
        parsed.hostname,
      )
    ) {
      return "Private network webhook endpoints are not allowed";
    }
    return null;
  } catch {
    return "Invalid webhook URL";
  }
}

export function validateWebhookEvents(events: string[]): string[] {
  return events.filter((event) => WEBHOOK_EVENTS.has(event));
}

export async function retryDueWebhookDeliveries(limit = 50) {
  const deliveries = await db.webhookDelivery.findMany({
    where: {
      status: { in: ["PENDING", "FAILED", "RETRYING"] },
      nextRetryAt: { lte: new Date() },
    },
    orderBy: { createdAt: "asc" },
    take: limit,
    include: { webhook: true },
  });

  let retried = 0;
  let succeeded = 0;
  let failed = 0;

  for (const delivery of deliveries) {
    retried += 1;
    const webhook = delivery.webhook;
    if (!webhook.active) {
      failed += 1;
      continue;
    }

    const events = Array.isArray(webhook.events)
      ? (webhook.events as string[])
      : (JSON.parse(String(webhook.events)) as string[]);

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      "User-Agent": "ScriptShield-Webhook/2.0",
    };

    if (webhook.secretEncrypted) {
      const bodyForDelivery = JSON.stringify({
        event: delivery.event,
        timestamp: new Date().toISOString(),
        data: {},
      });
      headers["X-Hub-Signature-256"] = signPayload(
        bodyForDelivery,
        decrypt(webhook.secretEncrypted),
      );
    }

    try {
      const response = await fetch(webhook.url, {
        method: "POST",
        headers,
        body: JSON.stringify({
          event: delivery.event,
          timestamp: new Date().toISOString(),
          data: {},
        }),
        signal: AbortSignal.timeout(5000),
      });

      await db.webhookDelivery.update({
        where: { id: delivery.id },
        data: {
          status: response.ok ? "DELIVERED" : "RETRYING",
          responseStatus: response.status,
          responseBody: response.ok ? null : await response.text(),
          nextRetryAt: response.ok
            ? null
            : new Date(
                Date.now() +
                  Math.min(60 * 60 * 1000, 1000 * 2 ** delivery.attempt),
              ),
        },
      });
      if (response.ok) succeeded += 1;
      else failed += 1;
    } catch (error) {
      await db.webhookDelivery.update({
        where: { id: delivery.id },
        data: {
          status: "RETRYING",
          responseBody:
            error instanceof Error ? error.message : "Webhook delivery failed",
          nextRetryAt: new Date(
            Date.now() + Math.min(60 * 60 * 1000, 1000 * 2 ** delivery.attempt),
          ),
        },
      });
      failed += 1;
    }
  }

  return { retried, succeeded, failed };
}

export async function dispatchWebhook(
  userId: string,
  event: string,
  payload: Record<string, unknown>,
) {
  if (!WEBHOOK_EVENTS.has(event)) return;

  try {
    const webhooks = await db.webhook.findMany({
      where: { userId, active: true },
    });

    const body = JSON.stringify({
      event,
      timestamp: new Date().toISOString(),
      data: payload,
    });

    for (const webhook of webhooks) {
      const events = Array.isArray(webhook.events)
        ? (webhook.events as string[])
        : (JSON.parse(String(webhook.events)) as string[]);

      if (!events.includes(event)) continue;

      const headers: Record<string, string> = {
        "Content-Type": "application/json",
        "User-Agent": "ScriptShield-Webhook/2.0",
      };

      if (webhook.secretEncrypted) {
        const secret = decrypt(webhook.secretEncrypted);
        headers["X-Hub-Signature-256"] = signPayload(body, secret);
      }

      const delivery = await db.webhookDelivery.create({
        data: {
          webhookId: webhook.id,
          event,
          status: "PENDING",
          attempt: 1,
        },
      });

      try {
        const response = await fetch(webhook.url, {
          method: "POST",
          headers,
          body,
          signal: AbortSignal.timeout(5000),
        });

        await db.webhookDelivery.update({
          where: { id: delivery.id },
          data: {
            status: response.ok ? "DELIVERED" : "FAILED",
            responseStatus: response.status,
            responseBody: response.ok ? null : await response.text(),
            nextRetryAt: response.ok
              ? null
              : new Date(Date.now() + 60 * 60 * 1000),
          },
        });
      } catch (error) {
        await db.webhookDelivery.update({
          where: { id: delivery.id },
          data: {
            status: "FAILED",
            responseBody:
              error instanceof Error
                ? error.message
                : "Webhook delivery failed",
            nextRetryAt: new Date(Date.now() + 60 * 60 * 1000),
          },
