  lastError?: string | null;
  p95LatencyMs?: number | null;
  errorRate5m?: number | null;
  failedWebhookDeliveries?: number;
};

async function getSetting<T>(key: string, fallback: T): Promise<T> {
  const setting = await db.siteSetting.findUnique({ where: { key } });
  if (!setting) return fallback;
  return setting.value as T;
}

export async function getSystemStatus(): Promise<SystemStatusValue> {
  const [
    backup,
    monitoring,
    p95LatencyMs,
    errorRate5m,
    failedWebhookDeliveries,
  ] = await Promise.all([
    getSetting<{
      status?: string;
      lastRunAt?: string | null;
      lastError?: string | null;
    }>("backup:lastRun", {}),
    getSetting<{
      status?: string;
      lastRunAt?: string | null;
      lastError?: string | null;
    }>("monitoring:lastRun", {}),
    db.apiRequestMetric.aggregate({
      _avg: { latencyMs: true },
      where: { createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) } },
    }),
    db.apiRequestMetric.count({
      where: {
        createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) },
        statusCode: { gte: 500 },
      },
    }),
    db.webhookDelivery.count({ where: { status: "FAILED" } }),
  ]);

  const totalRequests5m = await db.apiRequestMetric.count({
    where: { createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) } },
  });

  return {
    status: backup.status || "unknown",
    lastRunAt: backup.lastRunAt || null,
    lastError: backup.lastError || null,
    p95LatencyMs: p95LatencyMs._avg.latencyMs || null,
    errorRate5m: totalRequests5m
      ? Number(((errorRate5m / totalRequests5m) * 100).toFixed(2))
      : 0,
    failedWebhookDeliveries,
  };
}

