#!/usr/bin/env node
const fs = require("node:fs");
const path = require("node:path");

function parseEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return {};

  const lines = fs.readFileSync(filePath, "utf8").split(/\r?\n/);
  const parsed = {};

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;

    const separatorIndex = trimmed.indexOf("=");
    if (separatorIndex === -1) continue;

    const key = trimmed.slice(0, separatorIndex).trim();
    let value = trimmed.slice(separatorIndex + 1).trim();

    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }

    parsed[key] = value;
  }

  return parsed;
}

const envPath = path.resolve(process.cwd(), ".env");
Object.assign(process.env, parseEnvFile(envPath));

const required = process.argv.slice(2);

if (!required.length) {
  console.error("Usage: node scripts/check-required-env.cjs DATABASE_URL [OTHER_VAR...]");
  process.exit(1);
}

const missing = required.filter((name) => !process.env[name]);

if (missing.length) {
  console.error(`Missing required environment variable(s): ${missing.join(", ")}`);
  console.error(`Check ${envPath} or configure these variables in your host dashboard before running migrations.`);
  process.exit(1);
}

