#!/usr/bin/env node
const { PrismaClient } = require("@prisma/client");

const prisma = new PrismaClient();

async function main() {
  const columns = await prisma.$queryRaw`
    SELECT column_name
    FROM information_schema.columns
    WHERE table_name = '_prisma_migrations'
      AND table_schema = 'public'
  `;

  const hasFailedColumn = columns.some((row) => row.column_name === 'failed');

  if (!hasFailedColumn) {
    const setClauses = ["finished_at = COALESCE(finished_at, NOW())"];

    if (columns.some((row) => row.column_name === "rollbacked_at")) {
      setClauses.push("rollbacked_at = COALESCE(rollbacked_at, NOW())");
    }

    if (columns.some((row) => row.column_name === "logs")) {
      setClauses.push("logs = COALESCE(logs, 'Recovered by FireLab startup')");
    }

    if (columns.some((row) => row.column_name === "applied_steps_count")) {
      setClauses.push("applied_steps_count = GREATEST(applied_steps_count, 1)");
    }

    const result = await prisma.$executeRawUnsafe(`
      UPDATE "_prisma_migrations"
      SET ${setClauses.join(", ")}
      WHERE finished_at IS NULL
    `);

    console.log(`Recovered ${result} Prisma migration record(s) without failed column.`);
    return;
  }

  const failed = await prisma.$queryRaw`
    SELECT migration_name, logs
    FROM "_prisma_migrations"
    WHERE failed = true
    ORDER BY started_at DESC
  `;

  if (!failed.length) {
    console.log("No failed Prisma migrations found.");
    return;
  }

  for (const row of failed) {
    const migrationName = row.migration_name;

    await prisma.$executeRaw`
      UPDATE "_prisma_migrations"
      SET failed = false,
          finished_at = NOW()
      WHERE migration_name = ${migrationName}
    `;

    console.log(`Recovered failed Prisma migration: ${migrationName}`);
  }
}

main()
  .catch((error) => {
    console.error("Prisma migration recovery failed:", error);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

#!/usr/bin/env node
const { execFileSync } = require("node:child_process");
const { PrismaClient } = require("@prisma/client");

const prisma = new PrismaClient();
const migrationName = "20260611194000_platform_feature_completeness";

async function main() {
  const existing = await prisma.$queryRaw`
    SELECT migration_name
    FROM "_prisma_migrations"
    WHERE migration_name = ${migrationName}
    LIMIT 1
  `;

  if (existing.length > 0) {
    console.log(`Prisma migration already recorded: ${migrationName}`);
    return;
  }

  try {
    execFileSync("npx", ["prisma", "migrate", "resolve", "--applied", migrationName], {
      stdio: "inherit",
    });
  } catch (error) {
    console.log(`Prisma migration resolve skipped for ${migrationName}.`);
  }
}

main()
  .catch((error) => {
    console.error(error);
    process.exitCode = 1;
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { db } from "@/lib/db";
import { decrypt, hashToken } from "@/lib/crypto";
import { createAuditLog } from "@/lib/audit-logger";
import { createSessionToken, deviceNameFromUserAgent, setSessionCookie } from "@/lib/auth-session";
import { getClientIp, getJson, hashIdentifier, rateLimit, verifyCsrf } from "@/lib/http";
import { verifyTotp } from "@/lib/otp";
import { z } from "zod";

const loginSchema = z.object({
  email: z.string().trim().toLowerCase().email().max(255),
  password: z.string().min(1).max(128),
  code: z.string().min(1).max(16).optional(),
});

export async function POST(req: Request) {
  if (!verifyCsrf(req)) {
    return NextResponse.json({ error: "CSRF validation failed" }, { status: 403 });
  }

  const ip = getClientIp(req);
  const userAgent = req.headers.get("user-agent") || undefined;
  const deviceName = deviceNameFromUserAgent(userAgent);
  const limited = await rateLimit(`auth:login:${ip}`, 8, 15 * 60 * 1000);
  if (!limited.success) {
    return NextResponse.json({ error: "Too many login attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });
  }

  try {
    const body = loginSchema.safeParse(await getJson(req));
    if (!body.success) {
      return NextResponse.json({ error: "Invalid login data", details: body.error.flatten() }, { status: 400 });
    }

    const { email, password, code } = body.data;
    const user = await db.user.findUnique({ where: { email } });

    if (!user) {
      await db.loginAttempt.create({ data: { email, success: false, reason: "USER_NOT_FOUND", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Invalid credentials" }, { status: 401 });
    }

    if (user.banned) {
      await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "BANNED", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Account is suspended" }, { status: 403 });
    }

    const isMatch = await bcrypt.compare(password, user.passwordHash);
    if (!isMatch) {
      await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "INVALID_PASSWORD", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Invalid credentials" }, { status: 401 });
    }

    if (user.twoFactorEnabled) {
      if (!code) {
        return NextResponse.json({ error: "2FA_REQUIRED", twoFactorRequired: true }, { status: 401 });
      }
      if (!verifyTotp(decrypt(user.twoFactorSecretEncrypted!), code)) {
        const recovery = await db.recoveryCode.findFirst({
          where: { userId: user.id, codeHash: hashToken(code.toUpperCase()), consumedAt: null },
        });
        if (!recovery) {
          await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "INVALID_2FA_OR_RECOVERY", ip, userAgent, deviceName } });
          return NextResponse.json({ error: "Invalid 2FA or recovery code" }, { status: 401 });
        }
        await db.recoveryCode.update({ where: { id: recovery.id }, data: { consumedAt: new Date() } });
      }
    }

    const { token } = await createSessionToken(user, req);

    await db.userDevice.upsert({
      where: { userId_fingerprintHash: { userId: user.id, fingerprintHash: hashIdentifier(`${ip}:${userAgent || "unknown"}`) } },
      update: {
        deviceName,
        lastIp: ip,
        lastDeviceInfo: userAgent,
        lastUserAgent: userAgent,
        lastSeenAt: new Date(),
      },
      create: {
        userId: user.id,
        fingerprintHash: hashIdentifier(`${ip}:${userAgent || "unknown"}`),
        deviceName,
        lastIp: ip,
        lastDeviceInfo: userAgent,
        lastUserAgent: userAgent,
      },
    });

    await db.loginAttempt.create({ data: { userId: user.id, email, success: true, ip, userAgent, deviceName } });
    await db.ipReputation.upsert({ where: { ip }, update: { lastSeenAt: new Date(), suspiciousLoginCount: { increment: 0 } }, create: { ip, score: 100, lastSeenAt: new Date() } });
    await createAuditLog(user.id, "USER_LOGIN", { username: user.username, email: user.email }, ip, req.headers.get("user-agent") || undefined);

    const response = NextResponse.json({
      message: "Login successful",
      user: {
        id: user.id,
        username: user.username,
        email: user.email,
        role: user.role,
        discordId: user.discordId,
        githubId: user.githubId,
        avatarUrl: user.avatarUrl,
        twoFactorEnabled: user.twoFactorEnabled,
        isVerified: user.isVerified,
        banned: user.banned,
      },
      token,
    });

    setSessionCookie(response, token);
    return response;
  } catch (error) {
    console.error("Login Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { createSessionToken, deviceNameFromUserAgent, setSessionCookie } from "@/lib/auth-session";
import { getClientIp, getJson, rateLimit, verifyCsrf } from "@/lib/http";
import { z } from "zod";

const registerSchema = z.object({
  username: z.string().trim().min(3).max(32).regex(/^[a-zA-Z0-9_]+$/),
  email: z.string().trim().toLowerCase().email().max(255),
  password: z.string().min(10).max(128),
});

export async function POST(req: Request) {
  if (!verifyCsrf(req)) {
    return NextResponse.json({ error: "CSRF validation failed" }, { status: 403 });
  }

  const ip = getClientIp(req);
  const limited = await rateLimit(`auth:register:${ip}`, 5, 60 * 60 * 1000);
  if (!limited.success) {
    return NextResponse.json({ error: "Too many registration attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });
  }

  try {
    const body = registerSchema.safeParse(await getJson(req));
    if (!body.success) {
      return NextResponse.json({ error: "Invalid registration data", details: body.error.flatten() }, { status: 400 });
    }

    const { username, email, password } = body.data;
    const [existingEmail, existingUsername] = await Promise.all([
      db.user.findFirst({ where: { email }, select: { id: true } }),
      db.user.findFirst({ where: { username: { equals: username, mode: "insensitive" } }, select: { id: true } }),
    ]);

    if (existingEmail) return NextResponse.json({ error: "Email already exists" }, { status: 409 });
    if (existingUsername) return NextResponse.json({ error: "Username already exists" }, { status: 409 });

    const passwordHash = await bcrypt.hash(password, 12);
    const user = await db.user.create({
      data: {
        username,
        email,
        passwordHash,
        role: process.env.INITIAL_ADMIN_EMAIL?.toLowerCase() === email ? "ADMIN" : "DEVELOPER",
        isVerified: false,
      },
    });

    const userAgent = req.headers.get("user-agent") || undefined;
    const deviceName = deviceNameFromUserAgent(userAgent);
    const { token } = await createSessionToken(user, req, { deviceName });

    await db.loginAttempt.create({ data: { userId: user.id, email: user.email, success: true, reason: "REGISTERED", ip, userAgent, deviceName } });
    await createAuditLog(user.id, "USER_REGISTER", { username, email: user.email, role: user.role }, ip, req.headers.get("user-agent") || undefined);

    const response = NextResponse.json({
      message: "User registered successfully",
      user: {
        id: user.id,
        username: user.username,
        email: user.email,
        role: user.role,
        twoFactorEnabled: user.twoFactorEnabled,
        isVerified: user.isVerified,
      },
      token,
    });

    setSessionCookie(response, token);
    return response;
  } catch (error) {
    console.error("Register Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { encrypt } from "@/lib/crypto";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";
import { createOAuthState } from "@/lib/oauth-helpers";
import { buildDiscordAuthorizationUrl, generatePkcePair } from "@/lib/discord-oauth";

export async function GET(req: Request) {
  const limited = await rateLimit(`auth:discord:start:${getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);

  if (!limited.success) {
    return NextResponse.json({ error: "Too many Discord auth attempts" }, { status: 429, headers });
  }

  try {
    const pkce = generatePkcePair();
    const stateRecord = await createOAuthState(null, encrypt(pkce.verifier));
    const response = NextResponse.redirect(buildDiscordAuthorizationUrl(stateRecord.state, pkce.challenge));

    for (const [key, value] of Object.entries(headers)) {
      response.headers.set(key, value);
    }

    return response;
  } catch (error) {
    console.error("Discord OAuth start failed:", error);
    return NextResponse.redirect("/auth/login?oauth=config");
  }
}

import { NextResponse } from "next/server";
import { decrypt, encrypt } from "@/lib/crypto";
import { createAuditLog } from "@/lib/audit-logger";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";
import {
  consumeOAuthState,
  createOAuthSession,
  isOAuthStateError,
  linkOAuthAccount,
  linkOrCreateOAuthUser,
  normalizeEmail,
  oauthErrorRedirect,
  upsertLinkedOAuthAccount,
} from "@/lib/oauth-helpers";
import {
  DiscordOAuthError,
  discordAvatarUrl,
  discordDisplayName,
  exchangeCodeForToken,
  fetchDiscordUser,
} from "@/lib/discord-oauth";

async function discordUnavailableRedirect(error: unknown) {
  console.error("Discord OAuth callback failed:", error);
  if (error instanceof DiscordOAuthError && error.code === "discord-token-missing") return oauthErrorRedirect("invalid-token");
  return oauthErrorRedirect("discord-unavailable");
}

export async function GET(req: Request) {
  const limited = await rateLimit(`auth:discord:callback:${getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);
  const url = new URL(req.url);
  const code = url.searchParams.get("code");
  const state = url.searchParams.get("state");
  const error = url.searchParams.get("error");

  if (!limited.success) {
    return NextResponse.json({ error: "Too many Discord auth attempts" }, { status: 429, headers });
  }

  if (error === "access_denied" || error === "unauthorized_client") return oauthErrorRedirect("cancelled");
  if (error || !code || !state) return oauthErrorRedirect("error");

  const stateValidation = await consumeOAuthState(state, req);
  if (isOAuthStateError(stateValidation)) return oauthErrorRedirect(stateValidation.error.replace("oauth=", ""));

  try {
    const codeVerifier = stateValidation.record.codeVerifierEncrypted ? decrypt(stateValidation.record.codeVerifierEncrypted) : undefined;
    const tokenData = await exchangeCodeForToken(code, codeVerifier);
    const discordUser = await fetchDiscordUser(tokenData.access_token);
    const email = normalizeEmail(discordUser.email) || `discord-${discordUser.id}@local.invalid`;
    const scopes = tokenData.scope ? tokenData.scope.split(" ").filter(Boolean) : ["identify", "email"];
    const avatarUrl = discordAvatarUrl(discordUser);

    const account = {
      provider: "DISCORD" as const,
      providerAccountId: String(discordUser.id),
      email,
      emailVerified: Boolean(discordUser.email),
      displayName: discordDisplayName(discordUser, discordUser.email),
      avatarUrl,
      accessTokenEncrypted: encrypt(tokenData.access_token),
      refreshTokenEncrypted: tokenData.refresh_token ? encrypt(tokenData.refresh_token) : undefined,
      expiresAt: tokenData.expires_in ? new Date(Date.now() + tokenData.expires_in * 1000) : null,
      scopes,
    };

    const resolved = await linkOrCreateOAuthUser(account, stateValidation.record.userId);
    if (typeof resolved.error === "string") return oauthErrorRedirect(resolved.error);

    const user = await linkOAuthAccount(resolved.user, account);
    await upsertLinkedOAuthAccount(user.id, account);
    await createAuditLog(user.id, "USER_DISCORD_LOGIN", { discordId: discordUser.id, email: user.email }, getClientIp(req), req.headers.get("user-agent") || undefined);

    return createOAuthSession(user, req, "discord");
  } catch (error) {
    return discordUnavailableRedirect(error);
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import {
  canonicalStringify,
  decryptObject,
  encryptObject,
  hashString,
  hashToken,
  verifySignature,
} from "@/lib/crypto";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { connectRedis, redis } from "@/lib/redis";
import { recordSecurityFailure } from "@/lib/ip-reputation";

const REPLAY_TTL_MS = 5 * 60 * 1000;
const replayCache = new Map<string, number>();

function getHeaderSignature(req: Request) {
  return req.headers.get("x-signature") || req.headers.get("X-Signature");
}

function parseBody(rawBody: string) {
  try {
    return JSON.parse(rawBody) as {
      key?: string;
      hwid?: string;
      scriptId?: string;
      nonce?: string;
      timestamp?: number;
      executor?: string;
    };
  } catch {
    return null;
  }
}

function pruneReplayCache(now: number) {
  for (const [key, expiresAt] of replayCache.entries()) {
    if (expiresAt <= now) replayCache.delete(key);
  }
}

async function checkAuthReplay(
  parsed: {
    key: string;
    hwid: string;
    scriptId: string;
    nonce?: string;
    timestamp?: number;
  },
  keyHash: string,
) {
  const nonce = typeof parsed.nonce === "string" ? parsed.nonce.trim() : "";
  if (!nonce) return { success: true as const };

  if (
    typeof parsed.timestamp === "number" &&
    Math.abs(Date.now() - parsed.timestamp) > REPLAY_TTL_MS
  ) {
    return { success: false as const, reason: "STALE_AUTH_RESPONSE" };
  }

  const replayKey = hashString(
    `${keyHash}:${parsed.scriptId}:${parsed.hwid}:${nonce}`,
  );

  if (process.env.REDIS_URL) {
    try {
      await connectRedis();
      if (redis.status === "ready") {
        const setResult = await redis.set(
          `script-auth:replay:${replayKey}`,
          "1",
          "EX",
          Math.floor(REPLAY_TTL_MS / 1000),
          "NX",
        );
        return {
          success: setResult === ("OK" as const) ? true : false,
          reason: "REPLAY_NONCE_REUSED",
        };
      }
    } catch {
      pruneReplayCache(Date.now());
    }
  }

  pruneReplayCache(Date.now());
  if (replayCache.has(replayKey)) {
    return { success: false as const, reason: "REPLAY_NONCE_REUSED" };
  }

  replayCache.set(replayKey, Date.now() + REPLAY_TTL_MS);
  return { success: true as const };
}

export async function POST(req: Request) {
  const startTime = Date.now();
  const ip = getClientIp(req);

  const limited = await rateLimit(`script-auth:${ip}`, 30, 60 * 1000);
  if (!limited.success) {
    return NextResponse.json(
      { error: "Too many authentication requests" },
      { status: 429, headers: getRateLimitHeaders(limited) },
    );
  }

  const reputation = await db.ipReputation.findUnique({ where: { ip } });
  if (reputation?.blocked) {
    return NextResponse.json(
      { error: "IP blocked by abuse detection" },
      { status: 403 },
    );
  }

  try {
    const rawBody = await req.text();
    const parsed = parseBody(rawBody);
    if (!parsed)
      return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return NextResponse.json(
        { error: "Required fields missing" },
        { status: 400 },
      );
    }

    const key = parsed.key as string;
    const hwid = parsed.hwid as string;
    const scriptId = parsed.scriptId as string;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuaEngine";
    const country =
      req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

    async function logAccess(
      success: boolean,
      reason: string,
      licenseId?: string,
    ) {
      await db.scriptAccessLog.create({
        data: {
          scriptId,
          licenseId,
          userId: null,
          ip,
          country,
          success,
          reason,
          createdAt: new Date(),
        },
      });
      if (!success) await recordSecurityFailure(ip, reason);
    }

    const apiSecret = process.env.API_SECRET_KEY;
    const signature = getHeaderSignature(req);
    if (apiSecret) {
      const canonical = canonicalStringify(parsed);
      if (!signature || !verifySignature(canonical, signature, apiSecret)) {
        await logAccess(false, "SIGNATURE_MISMATCH", scriptId);
        return NextResponse.json(
          { error: "Tampered payload or signature mismatch" },
          { status: 401 },
        );
      }
    }

    const keyHash = hashToken(key);
    const replayCheck = await checkAuthReplay(
      { key, hwid, scriptId, nonce: parsed.nonce, timestamp: parsed.timestamp },
      keyHash,
    );
    if (!replayCheck.success) {
      await logAccess(false, replayCheck.reason, scriptId);
      return NextResponse.json(
        {
          error:
            replayCheck.reason === "STALE_AUTH_RESPONSE"
              ? "Stale authentication response"
              : "Replay nonce reused",
        },
        { status: 401 },
      );
    }

    const license = await db.license.findUnique({
      where: { keyHash },
      include: {
        script: { include: { protectionProfile: true } },
        hwids: { orderBy: { createdAt: "desc" } },
      },
    });

    if (!license || license.scriptId !== scriptId) {
      await logAccess(false, "INVALID_LICENSE_OR_SCRIPT_BINDING", scriptId);
      return NextResponse.json(
        { error: "Invalid license or script binding match" },
        { status: 401 },
      );
    }

    if (license.script.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED", license.id);
      return NextResponse.json(
        { error: "Script is disabled" },
        { status: 403 },
      );
    }

    if (license.status === "UNREDEEMED") {
      await logAccess(false, "LICENSE_UNREDEEMED", license.id);
      return NextResponse.json(
        { error: "License must be redeemed first" },
        { status: 403 },
      );
    }
    if (license.status === "SUSPENDED") {
      await logAccess(false, "LICENSE_SUSPENDED", license.id);
      return NextResponse.json(
        { error: "License has been suspended" },
        { status: 403 },
      );
    }
    if (license.status === "BLACKLISTED") {
      await logAccess(false, "LICENSE_BLACKLISTED", license.id);
      return NextResponse.json(
        { error: "License is blacklisted" },
        { status: 403 },
      );
    }
    if (
      license.status === "EXPIRED" ||
      (license.expiresAt && new Date() > license.expiresAt)
    ) {
      if (license.status !== "EXPIRED") {
        await db.license.update({
          where: { id: license.id },
          data: { status: "EXPIRED" },
        });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      return NextResponse.json(
        { error: "License subscription has expired" },
        { status: 403 },
      );
    }

    let hwidRecord = await db.hwid.findFirst({
      where: { licenseId: license.id, fingerprintHash },
    });

    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        await logAccess(false, "HWID_MISMATCH", license.id);
        return NextResponse.json(
          { error: "HWID mismatch. Reset HWID from the developer dashboard." },
          { status: 401 },
        );
      }

      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: {
            licenseId: license.id,
            fingerprintHash,
            source: "auth",
            lastIp: ip,
            lastDeviceInfo: req.headers.get("user-agent") || "LuaEngine",
          },
        });
      } else {
        await db.hwid.update({
          where: { id: hwidRecord.id },
          data: {
            lastIp: ip,
            lastDeviceInfo: req.headers.get("user-agent") || "LuaEngine",
          },
        });
      }
    }

    const maxActivations = license.script.protectionProfile?.maxActivations;
    if (maxActivations) {
      const recentActivationCount = await db.activation.count({
        where: {
          licenseId: license.id,
          success: true,
          createdAt: { gte: new Date(Date.now() - 24 * 60 * 60 * 1000) },
        },
      });

      if (recentActivationCount >= maxActivations) {
        await logAccess(false, "MAX_ACTIVATIONS_REACHED", license.id);
        return NextResponse.json(
          { error: "Maximum activation count reached" },
          { status: 429 },
        );
      }
    }

    await db.activation.create({
      data: {
        licenseId: license.id,
        hwidId: hwidRecord?.id || null,
        fingerprintHash,
        ip,
        country,
        deviceInfo: req.headers.get("user-agent") || "LuaEngine",
        userAgent: req.headers.get("user-agent") || "LuaEngine",
        success: true,
      },
    });

    await logAccess(true, "AUTH_SUCCESS", license.id);

    const scriptPayload = decryptObject<{ key: string }>(
      license.script.contentEncrypted,
    ).key;
    const encryptedData = encryptObject({
      success: true,
      execution_payload: scriptPayload,
      version: license.script.version,
      timestamp: Date.now(),
      licenseType: license.type,
      expiresAt: license.expiresAt?.toISOString() || null,
    });
    const [iv, ciphertext, tag] = encryptedData.split(".");

    return NextResponse.json(
      {
        encrypted_module: encryptedData,
        iv,
        ciphertext,
        tag,
        message: "Authentication successful",
      },
      {
        headers: {
          ...getRateLimitHeaders(limited),
          "X-Response-Time-Ms": (Date.now() - startTime).toString(),
          "Cache-Control": "private, no-store",
        },
      },
    );
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { getAuthenticatedUser, getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";
import { DiscordOAuthError, getDiscordUserWithFreshToken } from "@/lib/discord-oauth";

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  const limited = await rateLimit(`auth:discord:refresh:${user?.id || getClientIp(req)}`, 5, 60 * 1000);
  const headers = getRateLimitHeaders(limited);

  if (!limited.success) {
    return NextResponse.json({ error: "Too many Discord token refresh attempts" }, { status: 429, headers });
  }

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401, headers });
  }

  try {
    const discordUser = await getDiscordUserWithFreshToken(user.id);
    return NextResponse.json({ user: discordUser }, { headers });
  } catch (error) {
    console.error("Discord token refresh failed:", error);
    const status = error instanceof DiscordOAuthError && error.code === "discord-refresh-missing" ? 404 : 503;
    return NextResponse.json({ error: "Discord token refresh failed" }, { status, headers });
  }
}

