import { NextResponse } from "next/server";
import { cookies } from "next/headers";
import { db } from "@/lib/db";
import { decryptObject, randomToken } from "@/lib/crypto";
import { createAuditLog } from "@/lib/audit-logger";
import { getClientIp, getJson } from "@/lib/http";
import {
  createOAuthSession,
  getAvailableUsername,
  linkOAuthAccount,
  normalizeEmail,
  sanitizeUsername,
  upsertLinkedOAuthAccount,
} from "@/lib/oauth-helpers";
import type { OAuthAccount } from "@/lib/oauth-helpers";

const pendingCookie = "pending_oauth";

async function getPending(req: Request) {
  const cookieStore = await cookies();
  const value = cookieStore.get(pendingCookie)?.value;
  if (!value) return null;
  return decryptObject<OAuthAccount>(value);
}

export async function GET(req: Request) {
  try {
    const pending = await getPending(req);
    if (!pending) return NextResponse.json({ error: "OAuth session expired" }, { status: 400 });
    return NextResponse.json({ provider: pending.provider, username: pending.displayName, email: pending.email || "", avatarUrl: pending.avatarUrl });
  } catch (error) {
    console.error("OAuth username GET error:", error);
    return NextResponse.json({ error: "OAuth session expired" }, { status: 400 });
  }
}

export async function POST(req: Request) {
  try {
    const pending = await getPending(req);
    if (!pending) return NextResponse.json({ error: "OAuth session expired" }, { status: 400 });

    const body = (await getJson(req)) as { username?: unknown; email?: unknown };
    const email = normalizeEmail(typeof body.email === "string" ? body.email : pending.email);
    if (!email) return NextResponse.json({ error: "Email is required to finish OAuth setup" }, { status: 400 });

    const username = await getAvailableUsername(sanitizeUsername(typeof body.username === "string" ? body.username : "", pending.displayName));
    let user = await db.user.findUnique({ where: { email } });

    if (user) {
      const canLink = pending.provider === "DISCORD"
        ? !user.discordId || user.discordId === pending.providerAccountId
        : pending.provider === "GITHUB"
          ? !user.githubId || user.githubId === pending.providerAccountId
          : true;

      if (!canLink) return NextResponse.json({ error: "This OAuth account is already linked to another user" }, { status: 409 });

      user = await db.user.update({
        where: { id: user.id },
        data: {
          username,
          avatarUrl: pending.avatarUrl || user.avatarUrl,
          emailVerifiedAt: user.emailVerifiedAt || new Date(),
          isVerified: true,
          ...(pending.provider === "DISCORD" ? { discordId: pending.providerAccountId } : {}),
          ...(pending.provider === "GITHUB" ? { githubId: pending.providerAccountId } : {}),
        },
      });
    } else {
      user = await db.user.create({
        data: {
          email,
          username,
          passwordHash: randomToken(32),
          role: "USER",
          isVerified: true,
          emailVerifiedAt: new Date(),
          avatarUrl: pending.avatarUrl || null,
          ...(pending.provider === "DISCORD" ? { discordId: pending.providerAccountId } : {}),
          ...(pending.provider === "GITHUB" ? { githubId: pending.providerAccountId } : {}),
        },
      });
    }

    await linkOAuthAccount(user, pending);
    await upsertLinkedOAuthAccount(user.id, pending);
    await createAuditLog(user.id, pending.provider === "DISCORD" ? "USER_DISCORD_LOGIN" : pending.provider === "GITHUB" ? "USER_GITHUB_LOGIN" : "USER_GOOGLE_LOGIN", { email: user.email, username }, getClientIp(req), req.headers.get("user-agent") || undefined);

