import { NextResponse } from "next/server";
import { cookies } from "next/headers";
import { db } from "./db";
import { verifyToken } from "./jwt";
import { hashString, hashToken } from "./crypto";
import { isAllowedHost } from "./domains";
export { rateLimit } from "./rate-limit";

export interface SessionUser {
  id: string;
  username: string;
  email: string;
  role: "ADMIN" | "SELLER" | "DEVELOPER" | "USER";
  discordId?: string | null;
  githubId?: string | null;
  avatarUrl?: string | null;
  displayName?: string | null;
  twoFactorEnabled: boolean;
  isVerified: boolean;
  banned: boolean;
}

export function getCookieValue(req: Request | undefined, name: string) {
  if (req?.headers.get("cookie")) {
    const cookie = req.headers
      .get("cookie")!
      .split(";")
      .map((part) => part.trim())
      .find((part) => part.startsWith(`${name}=`));

    if (cookie) return decodeURIComponent(cookie.slice(name.length + 1));
  }

  return undefined;
}

async function getUserFromApiToken(token: string): Promise<SessionUser | null> {
  const apiToken = await db.apiToken.findUnique({
    where: { tokenHash: hashToken(token) },
    include: {
      user: {
        select: {
          id: true,
          username: true,
          email: true,
          role: true,
          discordId: true,
          githubId: true,
          avatarUrl: true,
          displayName: true,
          twoFactorEnabled: true,
          isVerified: true,
          banned: true,
        },
      },
    },
  });

  if (
    !apiToken ||
    !apiToken.active ||
    apiToken.blacklisted ||
    (apiToken.expiresAt && apiToken.expiresAt < new Date())
  ) {
    await db.apiToken
      .deleteMany({ where: { tokenHash: hashToken(token) } })
      .catch(() => undefined);
    return null;
  }

  await db.apiToken.update({
    where: { id: apiToken.id },
    data: { lastUsedAt: new Date() },
  });

  if (!apiToken.user || apiToken.user.banned) return null;
  return apiToken.user;
}

export async function getJson<T>(req: Request): Promise<T> {
  try {
    return (await req.json()) as T;
  } catch {
    throw new Error("Invalid JSON body");
  }
}

export function getClientIp(req: Request): string {
  const forwarded = req.headers.get("x-forwarded-for");
  if (forwarded) {
    return forwarded.split(",")[0]?.trim() || "unknown";
  }
  return req.headers.get("x-real-ip") || "unknown";
}

export function isUnsafeMethod(method: string) {
  return !["GET", "HEAD", "OPTIONS", "TRACE"].includes(method);
}

export function verifyCsrf(req: Request): boolean {
  if (!isUnsafeMethod(req.method)) return true;
  if (process.env.NODE_ENV !== "production") return true;

  const origin = req.headers.get("origin");
  const host = req.headers.get("host");
  const referer = req.headers.get("referer");

  if (origin) {
    try {
      return isAllowedHost(new URL(origin).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  if (referer) {
    try {
      return isAllowedHost(new URL(referer).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  return true;
}

export async function getAuthenticatedUser(
  req?: Request,
): Promise<SessionUser | null> {
  const cookieStore = await cookies();
  let token = getCookieValue(req, "token") || cookieStore.get("token")?.value;

  if (!token && req?.headers.get("authorization")?.startsWith("Bearer ")) {
    token = req.headers.get("authorization")!.substring(7);
  }

  if (!token) return null;

  const apiTokenUser = await getUserFromApiToken(token);
  if (apiTokenUser) return apiTokenUser;

  const decoded = verifyToken(token);
  if (!decoded) return null;

  const session = await db.session.findUnique({
    where: { sessionToken: token },
    select: { expiresAt: true, revokedAt: true, userId: true },
  });

  if (
    !session ||
    session.revokedAt ||
    session.expiresAt < new Date() ||
    session.userId !== decoded.userId
  ) {
    await db.session
      .deleteMany({
        where: {
          sessionToken: token,
          OR: [{ expiresAt: { lt: new Date() } }, { revokedAt: { not: null } }],
        },
      })
      .catch(() => undefined);
    return null;
  }

  await db.session.updateMany({
    where: { sessionToken: token },
    data: { lastUsedAt: new Date() },
  });

  const user = await db.user.findUnique({
    where: { id: decoded.userId },
    select: {
      id: true,
      username: true,
      email: true,
      role: true,
      discordId: true,
      githubId: true,
      avatarUrl: true,
      displayName: true,
      twoFactorEnabled: true,
      isVerified: true,
      banned: true,
    },
  });

  if (!user || user.banned) return null;
  return user;
}

