import { createHash } from "crypto";
import { db } from "./db";
import { decrypt, verifySignature } from "./crypto";

const replayCache = new Map<string, number>();

export async function getInboundSecret(provider: string) {
  const record = await db.inboundWebhookSecret.findUnique({
    where: { provider },
  });
  if (!record || !record.active) return null;
  return decrypt(record.secretEncrypted);
}

export async function verifyInboundWebhook(
  provider: string,
  rawBody: string,
  signature: string | null,
  timestamp: string | null,
) {
  const secret = await getInboundSecret(provider);
  if (!secret) return { ok: false, reason: "INBOUND_WEBHOOK_SECRET_MISSING" };

  const timestampNumber = Number(timestamp || "");
  if (
    !timestampNumber ||
    Math.abs(Date.now() - timestampNumber) > 5 * 60 * 1000
  ) {
    return { ok: false, reason: "INBOUND_WEBHOOK_STALE_TIMESTAMP" };
  }

  const replayKey = createHash("sha256")
    .update(`${provider}:${timestamp}:${rawBody}`)
    .digest("hex");
  const now = Date.now();
  if (replayCache.has(replayKey))
    return { ok: false, reason: "INBOUND_WEBHOOK_REPLAY_DETECTED" };
  replayCache.set(replayKey, now + 5 * 60 * 1000);
  for (const [key, expiresAt] of replayCache.entries()) {
    if (expiresAt <= now) replayCache.delete(key);
  }

  const signedPayload = `${timestamp}.${rawBody}`;
  if (!verifySignature(signedPayload, signature || "", secret)) {
    return { ok: false, reason: "INBOUND_WEBHOOK_SIGNATURE_MISMATCH" };
  }

  return { ok: true };
}


