import { db } from "./db";

export async function recordSecurityFailure(ip: string, reason: string) {
  if (!ip || ip === "unknown") return;

  await db.ipReputation.upsert({
    where: { ip },
    create: {
      ip,
      score: 90,
      suspiciousLoginCount: 1,
      blocked: false,
    },
    update: {
      score: { decrement: 10 },
      suspiciousLoginCount: { increment: 1 },
      lastSeenAt: new Date(),
    },
  });

  const reputation = await db.ipReputation.findUnique({ where: { ip } });
  if (reputation && reputation.score < 40) {
    await db.ipReputation.update({ where: { ip }, data: { blocked: true } });
  }
}

export async function blockIp(ip: string, reason: string) {
  if (!ip || ip === "unknown") return;
  await db.ipReputation.upsert({
    where: { ip },
    create: { ip, score: 0, suspiciousLoginCount: 1, blocked: true },
    update: {
      score: 0,
      suspiciousLoginCount: { increment: 1 },
      blocked: true,
      lastSeenAt: new Date(),
    },
  });
}


