import { db } from "./db";
import { decrypt, encrypt, signPayload } from "./crypto";

const WEBHOOK_EVENTS = new Set([
  "key.redeemed",
  "key.expired",
  "hwid.reset",
  "license.blacklisted",
  "script.updated",
]);

export function validateWebhookUrl(url: string): string | null {
  try {
    const parsed = new URL(url);
    if (!["http:", "https:"].includes(parsed.protocol))
      return "Only HTTP and HTTPS endpoints are allowed";
    if (
      parsed.hostname === "localhost" ||
      parsed.hostname === "127.0.0.1" ||
      parsed.hostname === "::1"
    )
      return null;
    if (
      /^(10\.|172\.(1[6-9]|2\d|3[0-1])\.|192\.168\.|169\.254\.)/.test(
        parsed.hostname,
      )
    ) {
      return "Private network webhook endpoints are not allowed";
    }
    return null;
  } catch {
    return "Invalid webhook URL";
  }
}

export function validateWebhookEvents(events: string[]): string[] {
  return events.filter((event) => WEBHOOK_EVENTS.has(event));
}

export async function retryDueWebhookDeliveries(limit = 50) {
  const deliveries = await db.webhookDelivery.findMany({
    where: {
      status: { in: ["PENDING", "FAILED", "RETRYING"] },
      nextRetryAt: { lte: new Date() },
    },
    orderBy: { createdAt: "asc" },
    take: limit,
    include: { webhook: true },
  });

  let retried = 0;
  let succeeded = 0;
  let failed = 0;

  for (const delivery of deliveries) {
    retried += 1;
    const webhook = delivery.webhook;
    if (!webhook.active) {
      failed += 1;
      continue;
    }

    const events = Array.isArray(webhook.events)
      ? (webhook.events as string[])
      : (JSON.parse(String(webhook.events)) as string[]);

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      "User-Agent": "ScriptShield-Webhook/2.0",
    };

    if (webhook.secretEncrypted) {
      const bodyForDelivery = JSON.stringify({
        event: delivery.event,
        timestamp: new Date().toISOString(),
        data: {},
      });
      headers["X-Hub-Signature-256"] = signPayload(
        bodyForDelivery,
        decrypt(webhook.secretEncrypted),
      );
    }

    try {
      const response = await fetch(webhook.url, {
        method: "POST",
        headers,
        body: JSON.stringify({
          event: delivery.event,
          timestamp: new Date().toISOString(),
          data: {},
        }),
        signal: AbortSignal.timeout(5000),
      });

      await db.webhookDelivery.update({
        where: { id: delivery.id },
        data: {
          status: response.ok ? "DELIVERED" : "RETRYING",
          responseStatus: response.status,
          responseBody: response.ok ? null : await response.text(),
          nextRetryAt: response.ok
            ? null
            : new Date(
                Date.now() +
                  Math.min(60 * 60 * 1000, 1000 * 2 ** delivery.attempt),
              ),
        },
      });
      if (response.ok) succeeded += 1;
      else failed += 1;
    } catch (error) {
      await db.webhookDelivery.update({
        where: { id: delivery.id },
        data: {
          status: "RETRYING",
          responseBody:
            error instanceof Error ? error.message : "Webhook delivery failed",
          nextRetryAt: new Date(
            Date.now() + Math.min(60 * 60 * 1000, 1000 * 2 ** delivery.attempt),
          ),
        },
      });
      failed += 1;
    }
  }

  return { retried, succeeded, failed };
}

export async function dispatchWebhook(
  userId: string,
  event: string,
  payload: Record<string, unknown>,
) {
  if (!WEBHOOK_EVENTS.has(event)) return;

  try {
    const webhooks = await db.webhook.findMany({
      where: { userId, active: true },
    });

    const body = JSON.stringify({
      event,
      timestamp: new Date().toISOString(),
      data: payload,
    });

    for (const webhook of webhooks) {
      const events = Array.isArray(webhook.events)
        ? (webhook.events as string[])
        : (JSON.parse(String(webhook.events)) as string[]);

      if (!events.includes(event)) continue;

      const headers: Record<string, string> = {
        "Content-Type": "application/json",
        "User-Agent": "ScriptShield-Webhook/2.0",
      };

      if (webhook.secretEncrypted) {
        const secret = decrypt(webhook.secretEncrypted);
        headers["X-Hub-Signature-256"] = signPayload(body, secret);
      }

      const delivery = await db.webhookDelivery.create({
        data: {
          webhookId: webhook.id,
          event,
          status: "PENDING",
          attempt: 1,
        },
      });

      try {
        const response = await fetch(webhook.url, {
          method: "POST",
          headers,
          body,
          signal: AbortSignal.timeout(5000),
        });

        await db.webhookDelivery.update({
          where: { id: delivery.id },
          data: {
            status: response.ok ? "DELIVERED" : "FAILED",
            responseStatus: response.status,
            responseBody: response.ok ? null : await response.text(),
            nextRetryAt: response.ok
              ? null
              : new Date(Date.now() + 60 * 60 * 1000),
          },
        });
      } catch (error) {
        await db.webhookDelivery.update({
          where: { id: delivery.id },
          data: {
            status: "FAILED",
            responseBody:
              error instanceof Error
                ? error.message
                : "Webhook delivery failed",
            nextRetryAt: new Date(Date.now() + 60 * 60 * 1000),
          },
        });
      }
    }
  } catch (error) {
    console.error("Error dispatching webhooks:", error);
  }
}

import { redis } from "./redis";

export interface RateLimitResult {
  success: boolean;
  limit: number;
  remaining: number;
  reset: number;
}

const localWindows = new Map<string, { count: number; resetAt: number }>();

async function redisRateLimit(key: string, limit: number, windowMs: number): Promise<RateLimitResult> {
  const now = Date.now();
  const resetAt = now + windowMs;
  const multi = redis.multi();
  multi.incr(key);
  multi.expire(key, Math.ceil(windowMs / 1000));
  const results = await multi.exec();
  if (!results) {
    return localRateLimit(key, limit, windowMs);
  }

  const [count] = results;

  const current = Number((count as any)?.[1] ?? 1);
  const ttl = await redis.ttl(key);
  const reset = now + Math.max(ttl, 1) * 1000;

  return {
    success: current <= limit,
    limit,
    remaining: Math.max(limit - current, 0),
    reset,
  };
}

function localRateLimit(key: string, limit: number, windowMs: number): RateLimitResult {
  const now = Date.now();
  const entry = localWindows.get(key);

  if (!entry || now > entry.resetAt) {
    localWindows.set(key, { count: 1, resetAt: resetAtFrom(now, windowMs) });
    return result(true, limit, limit - 1, entry?.resetAt ?? localWindows.get(key)!.resetAt);
  }

  if (entry.count >= limit) {
    return result(false, limit, 0, entry.resetAt);
  }

  entry.count += 1;
  return result(true, limit, limit - entry.count, entry.resetAt);
}

function resetAtFrom(now: number, windowMs: number) {
  return now + windowMs;
}

function result(success: boolean, limit: number, remaining: number, reset: number): RateLimitResult {
  return { success, limit, remaining, reset };
}

export async function rateLimit(key: string, limit = 60, windowMs = 60000): Promise<RateLimitResult> {
  if (redis.status === "ready") {
    return redisRateLimit(key, limit, windowMs);
  }

  return localRateLimit(key, limit, windowMs);
}

export function getRateLimitHeaders(result: RateLimitResult) {
  return {
    "X-RateLimit-Limit": result.limit.toString(),
    "X-RateLimit-Remaining": result.remaining.toString(),
    "X-RateLimit-Reset": Math.ceil(result.reset / 1000).toString(),
  };
}

import { db } from "./db";

type SystemStatusValue = {
  status?: string;
  lastRunAt?: string | null;
  lastError?: string | null;
  p95LatencyMs?: number | null;
  errorRate5m?: number | null;
  failedWebhookDeliveries?: number;
};

async function getSetting<T>(key: string, fallback: T): Promise<T> {
  const setting = await db.siteSetting.findUnique({ where: { key } });
  if (!setting) return fallback;
  return setting.value as T;
}

export async function getSystemStatus(): Promise<SystemStatusValue> {
  const [
    backup,
    monitoring,
    p95LatencyMs,
    errorRate5m,
    failedWebhookDeliveries,
  ] = await Promise.all([
    getSetting<{
      status?: string;
      lastRunAt?: string | null;
      lastError?: string | null;
    }>("backup:lastRun", {}),
    getSetting<{
      status?: string;
      lastRunAt?: string | null;
      lastError?: string | null;
    }>("monitoring:lastRun", {}),
    db.apiRequestMetric.aggregate({
      _avg: { latencyMs: true },
      where: { createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) } },
    }),
    db.apiRequestMetric.count({
      where: {
        createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) },
        statusCode: { gte: 500 },
      },
    }),
    db.webhookDelivery.count({ where: { status: "FAILED" } }),
  ]);

  const totalRequests5m = await db.apiRequestMetric.count({
    where: { createdAt: { gte: new Date(Date.now() - 5 * 60 * 1000) } },
  });

  return {
    status: backup.status || "unknown",
    lastRunAt: backup.lastRunAt || null,
    lastError: backup.lastError || null,
    p95LatencyMs: p95LatencyMs._avg.latencyMs || null,
    errorRate5m: totalRequests5m
      ? Number(((errorRate5m / totalRequests5m) * 100).toFixed(2))
      : 0,
    failedWebhookDeliveries,
  };
}

