import crypto from "crypto";

const DIGITS = 6;
const STEP_SECONDS = 30;
const WINDOW = 1;

function base32Decode(secret: string): Buffer {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
  const clean = secret.replace(/[^A-Z2-7]/gi, "").toUpperCase();
  let bits = "";
  let bytes: number[] = [];

  for (const char of clean) {
    const index = alphabet.indexOf(char);
    if (index === -1) continue;
    bits += index.toString(2).padStart(5, "0");
  }

  for (let i = 0; i + 8 <= bits.length; i += 8) {
    bytes.push(parseInt(bits.slice(i, i + 8), 2));
  }

  return Buffer.from(bytes);
}

function hotp(secret: Buffer, counter: number): string {
  const buffer = Buffer.alloc(8);
  for (let i = 7; i >= 0; i--) {
    buffer[i] = counter & 0xff;
    counter = Math.floor(counter / 256);
  }

  const hmac = crypto.createHmac("sha1", secret).update(buffer).digest();
  const offset = hmac[hmac.length - 1] & 0x0f;
  const code =
    ((hmac[offset] & 0x7f) << 24) |
    ((hmac[offset + 1] & 0xff) << 16) |
    ((hmac[offset + 2] & 0xff) << 8) |
    (hmac[offset + 3] & 0xff);

  return (code % 10 ** DIGITS).toString().padStart(DIGITS, "0");
}

export function generateTotp(secret: string, timestamp = Date.now()): string {
  const counter = Math.floor(timestamp / 1000 / STEP_SECONDS);
  return hotp(base32Decode(secret), counter);
}

export function verifyTotp(secret: string, token: string, timestamp = Date.now()): boolean {
  const cleanToken = token.replace(/\D/g, "");
  if (cleanToken.length !== DIGITS) return false;

  const counter = Math.floor(timestamp / 1000 / STEP_SECONDS);

  for (let i = -WINDOW; i <= WINDOW; i++) {
    const candidate = hotp(base32Decode(secret), counter + i);
    try {
      if (crypto.timingSafeEqual(Buffer.from(cleanToken), Buffer.from(candidate))) {
        return true;
      }
    } catch {
      return false;
    }
  }

  return false;
}

export function createOtpSecret(): string {
  const random = crypto.randomBytes(20);
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
  let output = "";
  for (let i = 0; i < random.length; i++) {
    output += alphabet[random[i] % alphabet.length];
  }
  return output;
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { decryptObject, encryptObject, randomToken } from "@/lib/crypto";
import { createSessionToken, setSessionCookie } from "@/lib/auth-session";
import { verifyToken } from "@/lib/jwt";

export type OAuthProvider = "discord" | "google" | "github";
export type OAuthProviderModel = "DISCORD" | "GOOGLE" | "GITHUB";
export type PendingOAuthProvider = OAuthProviderModel;

export const providerModel: Record<OAuthProvider, OAuthProviderModel> = {
  discord: "DISCORD",
  google: "GOOGLE",
  github: "GITHUB",
};

export type OAuthAccount = {
  provider: OAuthProviderModel;
  providerAccountId: string;
  email?: string | null;
  emailVerified?: boolean;
  displayName: string;
  avatarUrl?: string | null;
  accessTokenEncrypted: string;
  refreshTokenEncrypted?: string;
  expiresAt?: Date | null;
  scopes?: string[];
};

export type PendingOAuth = OAuthAccount & {
  email?: string | null;
};

export function normalizeEmail(email?: string | null) {
  return email?.trim().toLowerCase() || null;
}

export function usernameFromEmail(email: string) {
  return sanitizeUsername(email.split("@")[0], "user") || "user";
}

export function sanitizeUsername(username: string, fallback: string) {
  const clean = (username || fallback || "user").replace(/[^a-zA-Z0-9_]/g, "_").replace(/^_+|_+$/g, "").slice(0, 32);
  return clean || "user";
}

export async function getAvailableUsername(base: string) {
  const clean = sanitizeUsername(base, "user");
  for (let index = 0; index < 100; index += 1) {
    const candidate = index === 0 ? clean : `${clean.slice(0, 30)}_${index + 1}`;
    const exists = await db.user.findFirst({
      where: { username: { equals: candidate, mode: "insensitive" } },
      select: { id: true },
    });
    if (!exists) return candidate;
  }

  return `${clean.slice(0, 24)}_${randomToken(4)}`;
}

export async function createOAuthState(userId?: string | null, codeVerifierEncrypted?: string | null) {
  await db.oAuthState.deleteMany({
    where: { createdAt: { lt: new Date(Date.now() - 10 * 60 * 1000) } },
  });

  return db.oAuthState.create({
    data: {
      userId: userId || null,
      state: randomToken(24),
      codeVerifierEncrypted: codeVerifierEncrypted || null,
    },
  });
}

function parseCookieHeader(header?: string | null) {
  const cookies: Record<string, string> = {};
  if (!header) return cookies;

  for (const part of header.split(";")) {
    const index = part.indexOf("=");
    if (index === -1) continue;
    const key = part.slice(0, index).trim();
    const value = part.slice(index + 1).trim();
    cookies[key] = decodeURIComponent(value);
  }

  return cookies;
}

async function getOAuthSessionUserId(req: Request) {
  const token = parseCookieHeader(req.headers.get("cookie"))["token"];
  if (!token) return null;

  const decoded = verifyToken(token);
  if (!decoded) return null;

  const session = await db.session.findUnique({
    where: { sessionToken: token },
    select: { userId: true, expiresAt: true, revokedAt: true },
  });

  if (!session || session.revokedAt || session.expiresAt < new Date() || session.userId !== decoded.userId) return null;
  return session.userId;
}

export async function validateOAuthState(state: string | null, req: Request) {
  if (!state) return { error: "oauth=error" as const };

  await db.oAuthState.deleteMany({
    where: { createdAt: { lt: new Date(Date.now() - 10 * 60 * 1000) } },
  });

  const record = await db.oAuthState.findUnique({ where: { state } });
  if (!record) return { error: "oauth=invalid-state" as const };

  if (record.userId) {
    const sessionUserId = await getOAuthSessionUserId(req);
    if (sessionUserId !== record.userId) {
      await db.oAuthState.delete({ where: { id: record.id } }).catch(() => undefined);
      return { error: "oauth=invalid-state" as const };
    }
  }

  return { record };
}

export async function consumeOAuthState(state: string | null, req: Request) {
  const validation = await validateOAuthState(state, req);
  if ("error" in validation) return validation;

  await db.oAuthState.delete({ where: { id: validation.record.id } });
  return { record: validation.record };
}

export function isOAuthStateError(value: { error?: unknown } | { record: unknown }): value is { error: string } {
  return typeof (value as { error?: unknown }).error === "string";
}

export function oauthErrorRedirect(reason: string) {
  return NextResponse.redirect(`/auth/login?oauth=${reason}`);
}

export function createPendingOAuthResponse(pending: PendingOAuth) {
  const response = NextResponse.redirect("/auth/oauth-username");
  response.cookies.set("pending_oauth", encryptObject(pending), {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: 60 * 10,
  });
  return response;
}

export async function createOAuthSession(user: { id: string; email: string; role: string }, req: Request, provider: OAuthProvider) {
  const { token } = await createSessionToken(user, req);
  const response = NextResponse.redirect(`/dashboard?oauth=${provider}`);
  setSessionCookie(response, token);
  return response;
}

function providerUserIdField(provider: OAuthProviderModel) {
  if (provider === "DISCORD") return "discordId";
  if (provider === "GITHUB") return "githubId";
  return null;
}

export async function assertProviderCanLink(user: { id: string; discordId?: string | null; githubId?: string | null }, provider: OAuthProviderModel, providerAccountId: string) {
  const existingLink = await db.linkedAccount.findFirst({
    where: {
      provider,
      providerAccountId,
      userId: { not: user.id },
    },
    select: { id: true },
  });

  if (existingLink) return false;

  const field = providerUserIdField(provider);
  if (!field) return true;

  const current = field === "discordId" ? user.discordId : user.githubId;
  return !current || current === providerAccountId;
}

export async function linkOrCreateOAuthUser(account: OAuthAccount, existingUserId?: string | null) {
  if (existingUserId) {
    const user = await db.user.findUnique({ where: { id: existingUserId } });
    if (!user || !(await assertProviderCanLink(user, account.provider, account.providerAccountId))) {
      return { error: "oauth-conflict" as const };
    }
    return { user };
  }

  const linked = await db.linkedAccount.findFirst({
    where: { provider: account.provider, providerAccountId: account.providerAccountId },
    include: { user: true },
  });

  if (linked) return { user: linked.user };

  const email = normalizeEmail(account.email) ?? `${account.providerAccountId}@local.invalid`;
  let user = email ? await db.user.findUnique({ where: { email } }) : null;

  if (user) {
    if (!(await assertProviderCanLink(user, account.provider, account.providerAccountId))) {
      return { error: "oauth-conflict" as const };
    }
    return { user };
  }

  const username = await getAvailableUsername(account.displayName);
  const field = providerUserIdField(account.provider);
  user = await db.user.create({
    data: {
      email,
      username,
      displayName: account.displayName,
      passwordHash: randomToken(32),
      role: "USER",
      isVerified: account.emailVerified ?? Boolean(email),
      emailVerifiedAt: account.emailVerified ? new Date() : null,
      avatarUrl: account.avatarUrl || null,
      ...(field === "discordId" ? { discordId: account.providerAccountId } : {}),
      ...(field === "githubId" ? { githubId: account.providerAccountId } : {}),
    },
  });

  return { user };
}

export async function linkOAuthAccount(user: { id: string; username: string; avatarUrl?: string | null; emailVerifiedAt?: Date | null; isVerified: boolean; discordId?: string | null; githubId?: string | null; displayName?: string | null }, account: OAuthAccount) {
  const field = providerUserIdField(account.provider);
  return db.user.update({
    where: { id: user.id },
    data: {
      displayName: account.displayName || user.displayName || user.username,
      avatarUrl: account.avatarUrl || user.avatarUrl,
      emailVerifiedAt: account.emailVerified ? user.emailVerifiedAt || new Date() : user.emailVerifiedAt,
      isVerified: account.emailVerified ? true : user.isVerified,
      ...(field === "discordId" ? { discordId: account.providerAccountId } : {}),
      ...(field === "githubId" ? { githubId: account.providerAccountId } : {}),
    },
  });
}

export async function upsertLinkedOAuthAccount(userId: string, account: OAuthAccount) {
  return db.linkedAccount.upsert({
    where: {
      userId_provider_providerAccountId: {
        userId,
        provider: account.provider,
        providerAccountId: account.providerAccountId,
      },
    },
    update: {
      accessTokenEncrypted: account.accessTokenEncrypted,
      refreshTokenEncrypted: account.refreshTokenEncrypted || null,
      expiresAt: account.expiresAt || null,
      scopes: account.scopes || [],
      lastSyncedAt: new Date(),
    },
    create: {
      userId,
      provider: account.provider,
      providerAccountId: account.providerAccountId,
      accessTokenEncrypted: account.accessTokenEncrypted,
      refreshTokenEncrypted: account.refreshTokenEncrypted || null,
      expiresAt: account.expiresAt || null,
      scopes: account.scopes || [],
    },
  });
}

type OAuthProvider = "discord" | "google" | "github";

const DEFAULT_OAUTH_ORIGIN = "http://127.0.0.1:3000";

function trimOrigin(origin: string) {
  return origin.replace(/\/+$/, "");
}

export function getOAuthRedirectOrigin() {
  if (process.env.OAUTH_REDIRECT_ORIGIN) return trimOrigin(process.env.OAUTH_REDIRECT_ORIGIN);
  if (process.env.NEXT_PUBLIC_APP_URL) return trimOrigin(process.env.NEXT_PUBLIC_APP_URL);
  if (process.env.VERCEL_URL) return trimOrigin(`https://${process.env.VERCEL_URL}`);
