  if (configuredUri) return trimOrigin(configuredUri);

  return `${getOAuthRedirectOrigin()}/api/auth/${provider}/callback`;
}

import { db } from "./db";
import { encryptObject, generateLicenseKey, hashToken } from "./crypto";

export async function createLicenseKeys(input: {
  scriptId: string;
  ownerId: string;
  type: "LIFETIME" | "SUBSCRIPTION";
  durationDays?: number | null;
  count: number;
  note?: string | null;
  hwidLock: boolean;
  groupId?: string | null;
  tags?: string[] | null;
  trial?: boolean;
  productId?: string | null;
  transferable?: boolean;
  keyPrefix?: string | null;
}) {
  const created: string[] = [];

  for (let i = 0; i < input.count; i++) {
    let key = generateLicenseKey();
    let exists = true;
    let attempts = 0;

    while (exists && attempts < 5) {
      exists = Boolean(await db.license.findUnique({ where: { keyHash: hashToken(key) }, select: { id: true } }));
      if (exists) key = generateLicenseKey(input.keyPrefix || undefined);
      attempts += 1;
    }

    if (exists) throw new Error("Unable to generate a unique license key after several attempts");

    created.push(key);
  }

  const expiresAt =
    input.type === "SUBSCRIPTION" && input.durationDays
      ? new Date(Date.now() + input.durationDays * 24 * 60 * 60 * 1000)
      : null;

  await db.license.createMany({
    data: created.map((key) => ({
      keyEncrypted: encryptObject({ key }),
      keyHash: hashToken(key),
      type: input.type,
      status: "UNREDEEMED",
      durationDays: input.type === "SUBSCRIPTION" ? input.durationDays ?? 30 : null,
      expiresAt,
      note: input.note ?? null,
      hwidLock: input.hwidLock,
      groupId: input.groupId || null,
      tags: input.tags || undefined,
      trial: input.trial ?? false,
      productId: input.productId || undefined,
      transferable: input.transferable ?? true,
      scriptId: input.scriptId,
      ownerId: input.ownerId,
    })),
  });

  return created;
}

import { createHash } from "crypto";
import { db } from "./db";
import { decrypt, verifySignature } from "./crypto";

const replayCache = new Map<string, number>();

export async function getInboundSecret(provider: string) {
  const record = await db.inboundWebhookSecret.findUnique({
    where: { provider },
  });
  if (!record || !record.active) return null;
  return decrypt(record.secretEncrypted);
}

export async function verifyInboundWebhook(
  provider: string,
  rawBody: string,
  signature: string | null,
  timestamp: string | null,
) {
  const secret = await getInboundSecret(provider);
  if (!secret) return { ok: false, reason: "INBOUND_WEBHOOK_SECRET_MISSING" };

  const timestampNumber = Number(timestamp || "");
  if (
    !timestampNumber ||
    Math.abs(Date.now() - timestampNumber) > 5 * 60 * 1000
  ) {
    return { ok: false, reason: "INBOUND_WEBHOOK_STALE_TIMESTAMP" };
  }

  const replayKey = createHash("sha256")
    .update(`${provider}:${timestamp}:${rawBody}`)
    .digest("hex");
  const now = Date.now();
  if (replayCache.has(replayKey))
    return { ok: false, reason: "INBOUND_WEBHOOK_REPLAY_DETECTED" };
  replayCache.set(replayKey, now + 5 * 60 * 1000);
  for (const [key, expiresAt] of replayCache.entries()) {
    if (expiresAt <= now) replayCache.delete(key);
  }

  const signedPayload = `${timestamp}.${rawBody}`;
  if (!verifySignature(signedPayload, signature || "", secret)) {
    return { ok: false, reason: "INBOUND_WEBHOOK_SIGNATURE_MISMATCH" };
  }

  return { ok: true };
}

