}

function normalizeHost(value: string | null | undefined) {
  if (!value) return "";
  return value.toLowerCase().replace(/:\d+$/, "");
}

function parseCsv(value: string | undefined) {
  return (value || "")
    .split(",")
    .map((part) => part.trim().toLowerCase())
    .filter(Boolean);
}

function hostFromUrl(value: string | undefined) {
  if (!value) return "";
  try {
    return new URL(value).host.toLowerCase();
  } catch {
    return "";
  }
}

export function getAppHost() {
  return (
    hostFromUrl(process.env.NEXT_PUBLIC_APP_URL) ||
    hostFromUrl(process.env.OAUTH_REDIRECT_ORIGIN)
  );
}

export function getAllowedHosts() {
  const hosts = new Set<string>();
  const appHost = getAppHost();
  if (appHost) hosts.add(appHost);
  for (const host of parseCsv(process.env.ALLOWED_CUSTOM_DOMAINS))
    hosts.add(host);
  return [...hosts];
}

export function isAllowedHost(host: string | null | undefined) {
  const normalized = normalizeHost(host);
  if (!normalized) return false;
  return getAllowedHosts().includes(normalized);
}

export function resolveVerifiedCustomDomain(host: string | null | undefined) {
  const normalized = normalizeHost(host);
  if (!normalized) return null;
  if (getAllowedHosts().includes(normalized))
    return { domain: normalized, verified: true };
  return null;
}

