import { NextResponse } from "next/server";
import { cookies } from "next/headers";
import { clearPendingOAuthCookie, clearSessionCookie, destroySession } from "@/lib/auth-session";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";

export async function POST(req: Request) {
  const cookieStore = await cookies();
  const token = cookieStore.get("token")?.value;
  const limited = await rateLimit(`auth:logout:${token || getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);

  if (!limited.success) {
    return NextResponse.json({ error: "Too many logout attempts" }, { status: 429, headers });
  }

  await destroySession(token);

  const response = NextResponse.json({ message: "Logged out" }, { headers });
  clearSessionCookie(response);
  clearPendingOAuthCookie(response);
  return response;
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { createSessionToken, deviceNameFromUserAgent, setSessionCookie } from "@/lib/auth-session";
import { getClientIp, getRateLimitHeaders, rateLimit, verifyCsrf } from "@/lib/http";

function canUseQuickAdminLogin() {
  return process.env.ENABLE_QUICK_ADMIN_LOGIN === "true" || (process.env.NODE_ENV !== "production" && process.env.ALLOW_QUICK_ADMIN_LOGIN_DEV === "true");
}

export async function POST(req: Request) {
  if (!verifyCsrf(req)) {
    return NextResponse.json({ error: "CSRF validation failed" }, { status: 403 });
  }

  if (!canUseQuickAdminLogin()) {
    return NextResponse.json({ error: "Quick admin login is disabled" }, { status: 403 });
  }

  const adminEmail = process.env.ADMIN_GMAIL?.trim().toLowerCase();
  if (!adminEmail) {
    return NextResponse.json({ error: "Admin Gmail is not configured" }, { status: 403 });
  }

  const ip = getClientIp(req);
  const limited = await rateLimit(`auth:quick-admin-login:${ip}`, 3, 15 * 60 * 1000);
  if (!limited.success) {
    return NextResponse.json({ error: "Too many quick admin login attempts" }, { status: 429, headers: getRateLimitHeaders(limited) });
  }

  try {
    const admin = await db.user.findFirst({
      where: { role: "ADMIN", email: { equals: adminEmail, mode: "insensitive" }, banned: false },
    });

    if (!admin) {
      return NextResponse.json({ error: "Only the configured Gmail can use admin login" }, { status: 403 });
    }

    if (admin.twoFactorEnabled) {
      return NextResponse.json({ error: "2FA is required for this admin account" }, { status: 403 });
    }

    await createAuditLog(admin.id, "QUICK_ADMIN_LOGIN", { username: admin.username, email: admin.email }, ip, req.headers.get("user-agent") || undefined);

    const { token } = await createSessionToken(admin, req, { deviceName: deviceNameFromUserAgent(req.headers.get("user-agent")) });
    const response = NextResponse.json({
      message: "Quick admin login successful",
      user: {
        id: admin.id,
        username: admin.username,
        email: admin.email,
        role: admin.role,
        discordId: admin.discordId,
        githubId: admin.githubId,
        avatarUrl: admin.avatarUrl,
        twoFactorEnabled: admin.twoFactorEnabled,
        isVerified: admin.isVerified,
        banned: admin.banned,
      },
    });

    setSessionCookie(response, token);
    return response;
  } catch (error) {
    console.error("Quick Admin Login Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { getAuthenticatedUser, getJson, rateLimit } from "@/lib/http";
import { hashToken, randomToken } from "@/lib/crypto";
import { db } from "@/lib/db";

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`email:verify:${user.id}`, 3, 60 * 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many verification emails requested" }, { status: 429 });

  const body = await getJson<{ callbackUrl?: string }>(req);
  const token = randomToken(32);
  const tokenHash = hashToken(token);
  const callbackUrl = body.callbackUrl || `${process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000"}/auth/verify-email`;
  const verificationUrl = `${callbackUrl}?token=${token}`;

  await db.emailVerificationToken.create({
    data: {
      userId: user.id,
      tokenHash,
      expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000),
    },
  });

  await db.emailNotification.create({
    data: {
      userId: user.id,
      to: user.email,
      subject: "FireLab email verification",
      body: verificationUrl,
      template: "email-verification",
      status: "PENDING",
    },
  });

  // In production, send through SendGrid/Resend/Mailgun here.
  console.log(`[DEV] Email verification URL for ${user.email}: ${verificationUrl}`);

  return NextResponse.json({ message: "Verification email queued", verificationUrl });
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { hashToken } from "@/lib/crypto";
import { z } from "zod";

const schema = z.object({ token: z.string().min(1) });

export async function POST(req: Request) {
  try {
    const body = schema.safeParse(await req.json());
    if (!body.success) return NextResponse.json({ error: "Invalid request" }, { status: 400 });

    const record = await db.emailVerificationToken.findUnique({
      where: { tokenHash: hashToken(body.data.token) },
      include: { user: true },
    });

    if (!record || record.expiresAt < new Date()) {
      return NextResponse.json({ error: "Invalid or expired verification token" }, { status: 400 });
    }

    await db.$transaction([
      db.user.update({
        where: { id: record.userId },
        data: { isVerified: true, emailVerifiedAt: new Date() },
      }),
      db.emailVerificationToken.delete({ where: { id: record.id } }),
    ]);

    return NextResponse.json({ message: "Email verified successfully" });
  } catch (error) {
    console.error("Email verification error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { getJson, rateLimit } from "@/lib/http";
import { hashToken, randomToken } from "@/lib/crypto";
import { db } from "@/lib/db";
import { z } from "zod";

const schema = z.object({ email: z.string().email() });

export async function POST(req: Request) {
  const limited = await rateLimit("password:reset:request", 5, 15 * 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many password reset requests" }, { status: 429 });

  try {
    const body = schema.safeParse(await getJson(req));
    if (!body.success) return NextResponse.json({ error: "Invalid email" }, { status: 400 });

    const user = await db.user.findUnique({ where: { email: body.data.email.toLowerCase() }, select: { id: true, email: true } });
    if (!user) {
      return NextResponse.json({ message: "If the email exists, a reset link has been sent" });
    }

    const token = randomToken(32);
    await db.passwordResetToken.create({
      data: {
        userId: user.id,
        tokenHash: hashToken(token),
        expiresAt: new Date(Date.now() + 30 * 60 * 1000),
      },
    });

