const GOOGLE_TOKEN_URL = "https://oauth2.googleapis.com/token";
const GOOGLE_USER_URL = "https://www.googleapis.com/oauth2/v2/userinfo";

async function exchangeCodeForToken(code: string) {
  const res = await fetch(GOOGLE_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: new URLSearchParams({
      client_id: process.env.GOOGLE_CLIENT_ID || "",
      client_secret: process.env.GOOGLE_CLIENT_SECRET || "",
      grant_type: "authorization_code",
      code,
      redirect_uri: getOAuthRedirectUri("google"),
    }),
  });

  if (!res.ok) throw new Error("Google token exchange failed");
  const data = (await res.json()) as { access_token: string; scope?: string };
  if (!data.access_token) throw new Error("Google access token missing");
  return data;
}

async function fetchGoogleUser(accessToken: string) {
  const res = await fetch(GOOGLE_USER_URL, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (!res.ok) throw new Error("Google user fetch failed");

  return res.json() as Promise<{
    id: string;
    email: string;
    email_verified: boolean;
    name?: string | null;
    picture?: string | null;
  }>;
}

export async function GET(req: Request) {
  const url = new URL(req.url);
  const code = url.searchParams.get("code");
  const state = url.searchParams.get("state");
  const error = url.searchParams.get("error");

  if (error || !code || !state) return oauthErrorRedirect("error");

  const stateValidation = await consumeOAuthState(state, req);
  if (isOAuthStateError(stateValidation)) return oauthErrorRedirect(stateValidation.error.replace("oauth=", ""));

  try {
    const tokenData = await exchangeCodeForToken(code);
    const googleUser = await fetchGoogleUser(tokenData.access_token);
    const email = normalizeEmail(googleUser.email);

    if (!email || !googleUser.email_verified) {
      return oauthErrorRedirect("email-not-verified");
    }

    const account = {
      provider: "GOOGLE" as const,
      providerAccountId: String(googleUser.id),
      email,
      displayName: googleUser.name || usernameFromEmail(email),
      avatarUrl: googleUser.picture || null,
      accessTokenEncrypted: encrypt(tokenData.access_token),
      scopes: tokenData.scope ? tokenData.scope.split(" ").filter(Boolean) : ["openid", "email", "profile"],
    };

    const resolved = await linkOrCreateOAuthUser(account, stateValidation.record.userId);
    if (typeof resolved.error === "string") return oauthErrorRedirect(resolved.error);

    const user = await linkOAuthAccount(resolved.user, account);
    await upsertLinkedOAuthAccount(user.id, account);
    await createAuditLog(user.id, "USER_GOOGLE_LOGIN", { googleId: googleUser.id, email: user.email }, getClientIp(req), req.headers.get("user-agent") || undefined);

    return createOAuthSession(user, req, "google");
  } catch (error) {
    console.error("Google OAuth Error:", error);
    return oauthErrorRedirect("error");
  }
}

