import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

type OAuthProvider = "DISCORD" | "GOOGLE" | "GITHUB";

const providerCopy: Record<OAuthProvider, { label: string; icon: React.ReactNode; accent: string; description: string }> = {
  DISCORD: {
    label: "Discord",
    icon: <MessageCircle className="h-7 w-7 text-white" />,
    accent: "bg-[#5865F2]",
    description: "Skip this to keep your Discord name.",
  },
  GOOGLE: {
    label: "Gmail",
    icon: <Chrome className="h-7 w-7 text-white" />,
    accent: "bg-gradient-to-br from-[#EA4335] via-[#FBBC05] to-[#34A853]",
    description: "Skip this to keep your Gmail name.",
  },
  GITHUB: {
    label: "GitHub",
    icon: <Github className="h-7 w-7 text-white" />,
    accent: "bg-white",
    description: "Skip this to keep your GitHub name.",
  },
};

export default function OAuthUsernamePage() {
  const router = useRouter();
  const [provider, setProvider] = useState<OAuthProvider | null>(null);
  const [email, setEmail] = useState("");
  const [avatarUrl, setAvatarUrl] = useState<string | null>(null);
  const [username, setUsername] = useState("");
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch("/api/auth/oauth-username")
      .then((res) => res.json())
      .then((data) => {
        if (!data.provider) throw new Error(data.error || "OAuth session expired");
        setProvider(data.provider);
        setEmail(data.email || "");
        setAvatarUrl(data.avatarUrl || null);
        setUsername(data.username || "");
      })
      .catch((err) => setError(err instanceof Error ? err.message : "OAuth session expired"))
      .finally(() => setLoading(false));
  }, []);

  const handleSubmit = async (event?: React.FormEvent) => {
    if (event) event.preventDefault();
    setError("");
    setSubmitting(true);

    try {
      const res = await fetch("/api/auth/oauth-username", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username: username.trim() || undefined, email: email.trim() || undefined }),
      });
      const data = await res.json();
      if (res.ok) {
        router.push("/dashboard?oauth=success");
      } else {
        setError(data.error || "Unable to finish setup");
      }
    } catch {
      setError("Unable to connect to the authentication service.");
    } finally {
      setSubmitting(false);
    }
  };

  const currentProvider = provider ? providerCopy[provider] : null;

  return (
    <AuthLayout
      eyebrow="Finish OAuth setup"
      title="Choose your display name"
      description="Complete your Script Shield profile without exposing provider secrets."
      sideTitle="Connect your identity securely."
      sideDescription="OAuth setup links your external account to a Script Shield workspace while keeping sensitive tokens server-side."
      points={[
        { title: "Provider identity", description: "Use your existing Discord, Gmail, or GitHub account." },
        { title: "Workspace profile", description: "Choose a display name and email for your dashboard." },
        { title: "No secret exposure", description: "OAuth tokens remain handled by the API routes." },
      ]}
    >
      <motion.div initial={{ opacity: 0, y: 18 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.45 }}>
        {error && <div className="mb-4 rounded-2xl border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm font-semibold text-red-200">{error}</div>}

        {loading ? (
          <div className="rounded-2xl border border-primary/10 bg-black/24 p-6 text-center text-sm text-muted-foreground">Loading OAuth session...</div>
        ) : (
          <form onSubmit={(event) => void handleSubmit(event)} className="space-y-5">
            <div className="flex justify-center">
              {currentProvider ? <div className={`flex h-16 w-16 items-center justify-center rounded-2xl shadow-red-glow ${currentProvider.accent}`}>{currentProvider.icon}</div> : null}
            </div>

            <div className="rounded-2xl border border-primary/10 bg-black/24 p-4">
              <p className="text-xs font-black uppercase tracking-[0.2em] text-muted-foreground">Connected account</p>
              <p className="mt-2 break-all text-sm font-bold text-white">{email || "Email required"}</p>
              {avatarUrl && <img src={avatarUrl} alt="OAuth avatar" className="mt-4 h-16 w-16 rounded-2xl border border-primary/20 object-cover" />}
            </div>

            {!email && (
              <div className="space-y-1.5">
                <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Email Address</label>
                <Input type="email" value={email} onChange={(event) => setEmail(event.target.value)} placeholder="name@example.com" required />
              </div>
            )}

            <div className="space-y-1.5">
              <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Display name</label>
              <div className="relative">
                <User className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input value={username} onChange={(event) => setUsername(event.target.value)} placeholder={currentProvider?.label || "Display name"} className="pl-9" />
              </div>
            </div>

            <Button type="submit" variant="glow" className="h-12 w-full" disabled={submitting}>
              {submitting ? "Finishing setup..." : "Continue"}
            </Button>
            <Button type="button" variant="outline" className="h-12 w-full" onClick={() => void handleSubmit()} disabled={submitting || !email}>
              Skip and use provider name
            </Button>
          </form>
        )}
      </motion.div>
    </AuthLayout>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { AppShell, DashboardLoading } from "@/components/dashboard/app-shell";

interface User {
  id: string;
  username: string;
  email: string;
  role: string;
  discordId?: string;
  avatarUrl?: string;
  displayName?: string;
}

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    async function fetchSession() {
      try {
        const res = await fetch("/api/auth/me");
        const data = await res.json();
        if (data.user) {
          setUser(data.user);
        } else {
          router.push("/auth/login");
        }
      } catch {
        router.push("/auth/login");
      } finally {
        setLoading(false);
      }
    }

    fetchSession();
  }, [router]);

  if (loading) return <DashboardLoading />;

  return <AppShell user={user}>{children}</AppShell>;
}

