import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { decryptObject } from "@/lib/crypto";
import { createLicenseKeys } from "@/lib/license";
import { getAuthenticatedUser, getJson, rateLimit } from "@/lib/http";
import { z } from "zod";

const generateSchema = z.object({
  scriptId: z.string().uuid(),
  type: z.enum(["LIFETIME", "SUBSCRIPTION"]).optional().default("LIFETIME"),
  durationDays: z.number().int().min(1).max(3650).optional(),
  count: z.number().int().min(1).max(100),
  note: z.string().max(200).optional(),
  hwidLock: z.boolean().optional().default(true),
  groupId: z.string().uuid().optional().nullable(),
  tags: z.array(z.string().max(40)).max(20).optional(),
  trial: z.boolean().optional().default(false),
  productId: z.string().max(80).optional().nullable(),
  transferable: z.boolean().optional().default(true),
});

function sanitizeLicense(license: any) {
  let key = "";
  try {
    key = decryptObject<{ key: string }>(license.keyEncrypted).key;
  } catch {
    key = "";
  }

  return {
    ...license,
    key,
    keyEncrypted: undefined,
    keyHash: undefined,
  };
}

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`licenses:list:${user.id}`, 60, 60 * 1000);
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many requests" },
      {
        status: 429,
        headers: { "X-RateLimit-Reset": limited.reset.toString() },
      },
    );

  const { searchParams } = new URL(req.url);
  const page = Math.max(Number(searchParams.get("page") || 1), 1);
  const take = Math.min(Number(searchParams.get("take") || 50), 100);
  const search = searchParams.get("search") || "";
  const status = searchParams.get("status") as any;

  const where: any =
    user.role === "ADMIN"
      ? {}
      : {
          OR: [
            { ownerId: user.id },
            { script: { team: { members: { some: { userId: user.id } } } } },
          ],
        };
  if (search) {
    where.OR = [
      { note: { contains: search, mode: "insensitive" } },
      { redeemedBy: { contains: search, mode: "insensitive" } },
    ];
  }
  if (status) where.status = status;

  const licenses = await db.license.findMany({
    where,
    include: {
      script: { select: { name: true } },
      owner: { select: { username: true } },
    },
    orderBy: { createdAt: "desc" },
    skip: (page - 1) * take,
    take,
  });

  return NextResponse.json({
    licenses: licenses.map(sanitizeLicense),
    page,
    take,
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user || !["ADMIN", "DEVELOPER", "SELLER"].includes(user.role))
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`licenses:create:${user.id}`, 10, 60 * 1000);
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many license generation attempts" },
      { status: 429 },
    );

  try {
    const body = generateSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        {
          error: "Invalid license generation request",
          details: body.error.flatten(),
        },
        { status: 400 },
      );

    const script = await db.script.findUnique({
      where: { id: body.data.scriptId },
      select: { id: true, name: true },
    });
    if (!script)
      return NextResponse.json({ error: "Script not found" }, { status: 404 });

    const keys = await createLicenseKeys({
      scriptId: script.id,
      ownerId: user.id,
      type: body.data.type,
      durationDays: body.data.durationDays,
      count: body.data.count,
      note: body.data.note,
      hwidLock: body.data.hwidLock,
      groupId: body.data.groupId,
      tags: body.data.tags || undefined,
      trial: body.data.trial,
      productId: body.data.productId,
      transferable: body.data.transferable,
    });

    await createAuditLog(
      user.id,
      "LICENSE_CREATE_BULK",
      { count: body.data.count, scriptId: script.id, scriptName: script.name },
      undefined,
      req.headers.get("user-agent") || undefined,
      "License",
      script.id,
    );

    return NextResponse.json({
      message: `Successfully generated ${body.data.count} license keys`,
      keys,
    });
  } catch (error) {
    console.error("POST Licenses Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { dispatchWebhook } from "@/lib/webhooks";
import { getClientIp, getJson, hashIdentifier, rateLimit } from "@/lib/http";
import { hashToken } from "@/lib/crypto";
import { z } from "zod";

const redeemSchema = z.object({
  key: z.string().min(8).max(64),
  redeemedBy: z.string().min(2).max(128),
  hwid: z.string().min(8).max(512).optional(),
});

export async function POST(req: Request) {
  const ip = getClientIp(req);
  const limited = await rateLimit(`license:redeem:${ip}`, 10, 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many redemption attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });

  try {
    const body = redeemSchema.safeParse(await getJson(req));
    if (!body.success) return NextResponse.json({ error: "License key and user identifier are required", details: body.error.flatten() }, { status: 400 });

    const { key, redeemedBy, hwid } = body.data;
    const keyHash = hashToken(key);
    const license = await db.license.findUnique({
      where: { keyHash },
      include: { script: true },
    });

    if (!license) return NextResponse.json({ error: "License key does not exist" }, { status: 404 });
    if (license.status !== "UNREDEEMED") return NextResponse.json({ error: `License key is already redeemed (Status: ${license.status})` }, { status: 400 });

    let expiresAt: Date | null = null;
    if (license.type === "SUBSCRIPTION" && license.durationDays) {
      expiresAt = new Date(Date.now() + license.durationDays * 24 * 60 * 60 * 1000);
    }

    const updated = await db.$transaction(async (tx) => {
      const licenseUpdate = await tx.license.update({
        where: { id: license.id },
        data: {
          status: "ACTIVE",
          redeemedBy,
          redeemedAt: new Date(),
          expiresAt,
        },
      });

      if (hwid && license.hwidLock) {
        await tx.hwid.create({
          data: {
            licenseId: license.id,
            fingerprintHash: hashIdentifier(hwid),
            source: "redeem",
            lastIp: ip,
          },
        }).catch(() => undefined);
      }

      return licenseUpdate;
    });

    await createAuditLog(license.ownerId, "LICENSE_REDEEM", { licenseId: license.id, redeemedBy, expiresAt }, ip, req.headers.get("user-agent") || undefined, "License", license.id);
    void dispatchWebhook(license.ownerId, "key.redeemed", {
      licenseId: license.id,
      redeemedBy,
      type: license.type,
      expiresAt: expiresAt?.toISOString() || "Lifetime",
      scriptName: license.script.name,
    });

    return NextResponse.json({ message: "License key successfully activated and redeemed!", license: updated });
  } catch (error) {
    console.error("Redeem License Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

