import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { decrypt, encrypt } from "@/lib/crypto";
import { createOtpSecret, verifyTotp } from "@/lib/otp";
import { getAuthenticatedUser, getJson } from "@/lib/http";
import { z } from "zod";

const setupSchema = z.object({ setup: z.literal(true) });
const enableSchema = z.object({ code: z.string().regex(/^\d{6}$/) });
const disableSchema = z.object({ code: z.string().regex(/^\d{6}$/) });

function otpUri(secret: string, email: string) {
  const issuer = encodeURIComponent("FireLab");
  const label = encodeURIComponent(email);
  return `otpauth://totp/${issuer}:${label}?secret=${secret}&issuer=${issuer}&algorithm=SHA1&digits=6&period=30`;
}

async function getCurrent2FAState(userId: string) {
  return db.user.findUnique({
    where: { id: userId },
    select: { twoFactorEnabled: true, twoFactorSecretEncrypted: true },
  });
}

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const dbUser = await getCurrent2FAState(user.id);

  return NextResponse.json({
    enabled: dbUser?.twoFactorEnabled || false,
    setupRequired: !dbUser?.twoFactorEnabled && !dbUser?.twoFactorSecretEncrypted,
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  try {
    const body = await getJson(req);
    const setup = setupSchema.safeParse(body);

    if (setup.success) {
      const existing = await getCurrent2FAState(user.id);
      const secret = existing?.twoFactorSecretEncrypted ? decrypt(existing.twoFactorSecretEncrypted) : createOtpSecret();

      await db.user.update({
        where: { id: user.id },
        data: { twoFactorSecretEncrypted: encrypt(secret), twoFactorEnabled: false },
      });

      return NextResponse.json({
        setupRequired: true,
        secret,
        uri: otpUri(secret, user.email),
      });
    }

    const verification = enableSchema.safeParse(body);
    if (!verification.success) return NextResponse.json({ error: "Invalid 2FA code", details: verification.error.flatten() }, { status: 400 });

    const existing = await getCurrent2FAState(user.id);
    if (!existing?.twoFactorSecretEncrypted) {
      return NextResponse.json({ error: "Create a 2FA setup secret before verification", details: { setupRequired: true } }, { status: 400 });
    }

    const secret = decrypt(existing.twoFactorSecretEncrypted);
    if (!verifyTotp(secret, verification.data.code)) {
      return NextResponse.json({ error: "Invalid 2FA code" }, { status: 400 });
    }

    await db.user.update({
      where: { id: user.id },
      data: { twoFactorSecretEncrypted: encrypt(secret), twoFactorEnabled: true },
    });

    await createAuditLog(user.id, "USER_2FA_ENABLE", {}, undefined, req.headers.get("user-agent") || undefined, "User", user.id);
    return NextResponse.json({ message: "2FA enabled successfully" });
  } catch (error) {
    console.error("2FA enable error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

export async function DELETE(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  try {
    const body = disableSchema.safeParse(await getJson(req));
    if (!body.success) return NextResponse.json({ error: "Invalid 2FA code", details: body.error.flatten() }, { status: 400 });

    const dbUser = await getCurrent2FAState(user.id);
    if (!dbUser?.twoFactorSecretEncrypted || !dbUser.twoFactorEnabled) {
      return NextResponse.json({ error: "2FA is not enabled" }, { status: 400 });
    }

    if (!verifyTotp(decrypt(dbUser.twoFactorSecretEncrypted), body.data.code)) {
      return NextResponse.json({ error: "Invalid 2FA code" }, { status: 400 });
    }

    await db.user.update({ where: { id: user.id }, data: { twoFactorEnabled: false, twoFactorSecretEncrypted: null } });
    await createAuditLog(user.id, "USER_2FA_DISABLE", {}, undefined, req.headers.get("user-agent") || undefined, "User", user.id);

    return NextResponse.json({ message: "2FA disabled successfully" });
  } catch (error) {
    console.error("2FA disable error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { hashToken } from "@/lib/crypto";
import { getAuthenticatedUser, getJson } from "@/lib/http";
import { z } from "zod";

const verifySchema = z.object({ code: z.string().regex(/^\d{4}-\d{4}-\d{4}$/) });

function generateRecoveryCodes(count = 10) {
  const alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  return Array.from({ length: count }, () => {
    const chunks = Array.from({ length: 3 }, () => Array.from({ length: 4 }, () => alphabet[Math.floor(Math.random() * alphabet.length)]).join(""));
    return chunks.join("-");
  });
}

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const count = await db.recoveryCode.count({ where: { userId: user.id, consumedAt: null } });
  return NextResponse.json({ count });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const codes = generateRecoveryCodes();
  await db.recoveryCode.updateMany({ where: { userId: user.id, consumedAt: null }, data: { consumedAt: new Date() } });

  await db.recoveryCode.createMany({
    data: codes.map((code) => ({ userId: user.id, codeHash: hashToken(code) })),
  });

  await createAuditLog(user.id, "USER_RECOVERY_CODES_ROTATED", { count: codes.length }, undefined, req.headers.get("user-agent") || undefined, "User", user.id);

  return NextResponse.json({ codes });
}

export async function DELETE(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const body = verifySchema.safeParse(await getJson(req));
  if (!body.success) return NextResponse.json({ error: "Invalid recovery code" }, { status: 400 });

  const code = body.data.code.toUpperCase();
  const record = await db.recoveryCode.findFirst({ where: { userId: user.id, codeHash: hashToken(code), consumedAt: null } });
  if (!record) return NextResponse.json({ error: "Invalid recovery code" }, { status: 400 });

  await db.recoveryCode.update({ where: { id: record.id }, data: { consumedAt: new Date() } });
  await createAuditLog(user.id, "USER_RECOVERY_CODE_USED", {}, undefined, req.headers.get("user-agent") || undefined, "User", user.id);

  return NextResponse.json({ message: "Recovery code consumed successfully" });
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { hashToken, randomToken } from "@/lib/crypto";
import { getAuthenticatedUser, getJson, rateLimit } from "@/lib/http";
import { z } from "zod";

const tokenSchema = z.object({
  name: z.string().min(2).max(64),
  expiresAt: z.string().datetime().optional(),
  expiresInHours: z.number().int().min(1).max(8760).optional(),
  permissions: z.array(z.string().max(40)).max(20).optional(),
});

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const tokens = await db.apiToken.findMany({
    where: { userId: user.id },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json({
    tokens: tokens.map((token) => ({
      id: token.id,
      name: token.name,
      prefix: token.prefix,
      permissions: token.permissions,
      expiresAt: token.expiresAt,
      active: token.active,
      blacklisted: token.blacklisted,
      blacklistReason: token.blacklistReason,
      lastUsedAt: token.lastUsedAt,
      createdAt: token.createdAt,
    })),
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(
    `api-token:create:${user.id}`,
    5,
    60 * 60 * 1000,
  );
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many token creation attempts" },
      { status: 429 },
    );

  try {
    const body = tokenSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        { error: "Invalid token request", details: body.error.flatten() },
        { status: 400 },
      );

    const rawToken = `ss_${randomToken(32)}`;
    const expiresAt = body.data.expiresAt
      ? new Date(body.data.expiresAt)
      : body.data.expiresInHours
        ? new Date(Date.now() + body.data.expiresInHours * 60 * 60 * 1000)
        : new Date(Date.now() + 12 * 60 * 60 * 1000);
    const token = await db.apiToken.create({
      data: {
        userId: user.id,
        name: body.data.name,
        tokenHash: hashToken(rawToken),
        prefix: rawToken.slice(0, 8),
        expiresAt,
        permissions: body.data.permissions || undefined,
        active: true,
        blacklisted: false,
      },
    });

    await createAuditLog(
      user.id,
      "API_TOKEN_CREATE",
      { tokenId: token.id, name: token.name },
      undefined,
      req.headers.get("user-agent") || undefined,
      "ApiToken",
      token.id,
    );

    return NextResponse.json({
      token: rawToken,
      tokenInfo: {
        id: token.id,
        name: token.name,
        prefix: token.prefix,
        expiresAt: token.expiresAt,
        active: token.active,
        blacklisted: token.blacklisted,
      },
    });
  } catch (error) {
    console.error("API Token create error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { encrypt } from "@/lib/crypto";
import { getAuthenticatedUser, getJson } from "@/lib/http";
import { validateWebhookEvents, validateWebhookUrl } from "@/lib/webhooks";
import { z } from "zod";

const webhookSchema = z.object({
  url: z.string().url(),
  events: z.preprocess((value) => (typeof value === "string" ? value.split(",").map((event) => event.trim()).filter(Boolean) : value), z.array(z.string()).min(1)),
  secret: z.string().min(16).max(128).optional(),
});

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const webhooks = await db.webhook.findMany({
    where: { userId: user.id },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json({
    webhooks: webhooks.map((webhook) => ({
      ...webhook,
      secret: webhook.secretEncrypted ? "active" : null,
      secretEncrypted: undefined,
    })),
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  try {
    const body = webhookSchema.safeParse(await getJson(req));
    if (!body.success) return NextResponse.json({ error: "Invalid webhook request", details: body.error.flatten() }, { status: 400 });

    const urlError = validateWebhookUrl(body.data.url);
    if (urlError) return NextResponse.json({ error: urlError }, { status: 400 });

    const events = validateWebhookEvents(body.data.events);
    if (events.length === 0) return NextResponse.json({ error: "No valid webhook events selected" }, { status: 400 });

    const webhook = await db.webhook.create({
      data: {
        userId: user.id,
        url: body.data.url,
        events,
        secretEncrypted: body.data.secret ? encrypt(body.data.secret) : null,
      },
    });

    await createAuditLog(user.id, "WEBHOOK_CREATE", { webhookId: webhook.id, url: webhook.url }, undefined, req.headers.get("user-agent") || undefined, "Webhook", webhook.id);

    return NextResponse.json({ message: "Webhook registered successfully", webhook });
  } catch (error) {
    console.error("POST Webhook Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

